const i={bleeding:{id:"bleeding",name:"Bleeding",icon:"🩸",color:"#9e2d2d",description:"Loses 1 HP at start of each day.",onDayStart:{damage:1}},poisoned:{id:"poisoned",name:"Poisoned",icon:"☠",color:"#5a7a3a",description:"Loses 1 HP at start of each day. WIL checks at -2.",onDayStart:{damage:1},statPenalty:{wil:-2}},exhausted:{id:"exhausted",name:"Exhausted",icon:"💤",color:"#8a8078",description:"All stat checks at -2. Removed by full rest.",statPenalty:{grt:-2,edg:-2}},stunned:{id:"stunned",name:"Stunned",icon:"⭐",color:"#b8961e",description:"Skips next turn in combat.",skipTurn:!0},dehydrated:{id:"dehydrated",name:"Dehydrated",icon:"💧",color:"#c7622a",description:"No water. Loses 2 HP at start of each day.",onDayStart:{damage:2}},starving:{id:"starving",name:"Starving",icon:"🍖",color:"#8a5a2a",description:"No food. Loses 1 HP at start of each day.",onDayStart:{damage:1}},frail:{id:"frail",name:"Frail",icon:"💀",color:"#c7622a",description:"Starving and dehydrated at once. Loses extra 2 HP/day. Clears when either condition resolves.",onDayStart:{damage:2}},festering:{id:"festering",name:"Festering",icon:"🩺",color:"#5a4a2a",description:"Wounds won't heal without food. Loses 1 extra HP/day.",onDayStart:{damage:1}},cold_exposure:{id:"cold_exposure",name:"Cold Exposure",icon:"❄",color:"#6a9ab8",description:"Without warmth or shelter, HP drains. Clears when fuel is available.",onDayStart:{damage:1}}},l=[{id:"ash_well_discovery",title:"THE BROKEN WELL",biomes:["ashfields"],weight:8,type:"discovery",illustration:"placeholder",narrative:"An old well sits at the crossroads, its stone lip cracked and scorched. Something has been carved into the base recently — rough letters, still fresh. The ash around it is undisturbed.",choices:[{text:"Read the inscription (Lore TN 8)",visibleCost:null,skillCheck:{skill:"history",stat:"wit",tn:8},outcomes:{success:{text:'The inscription warns: "Three days east, the road ends. Took us anyway." Beside it, a crude map scratched in the stone. You memorize it.',effects:[{type:"flag",key:"road_warning_known",value:!0},{type:"morale",value:-5},{type:"log",text:"You found a warning carved at the crossroads well."}]},failure:{text:"The letters are in an old script you cannot place. You move on with a hollow feeling in your gut.",effects:[{type:"morale",value:-3}]}}},{text:"Leave it alone",visibleCost:null,skillCheck:null,outcomes:{success:{text:"The road goes on. The inscription goes unread.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:0},{id:"deserter_begging",title:"THE DESERTER",biomes:["ashfields","ironmarch"],weight:10,type:"moral",illustration:"placeholder",narrative:"A soldier in a tattered imperial surcoat sits against a dead tree, hand outstretched. His uniform marks him as Iron Legion — empire men — but his eyes are hollow with hunger, not threat. He begs for anything: food, water, passage.",choices:[{text:"Give him rations (–2 Food)",visibleCost:"2 food",skillCheck:null,outcomes:{success:{text:"He takes the food with shaking hands and weeps. Between bites he murmurs about a ford three leagues north where the patrols don't watch. You file the information away.",effects:[{type:"food",value:-2},{type:"flag",key:"deserter_ford_known",value:!0},{type:"morale",value:5},{type:"log",text:"A deserter told you of an unguarded ford to the north."}]},failure:{text:"",effects:[]}}},{text:"Give him water only (–1 Water)",visibleCost:"1 water",skillCheck:null,outcomes:{success:{text:"He drinks it all at once and says nothing. He's still sitting there when you crest the next ridge.",effects:[{type:"water",value:-1},{type:"morale",value:2}]},failure:{text:"",effects:[]}}},{text:"Walk past him",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You don't look back. The road demands hard choices. Some in the party are quiet for hours afterward.",effects:[{type:"morale",value:-8}]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"ash_voices",title:"VOICES IN THE ASH",biomes:["ashfields"],weight:7,type:"exploration",illustration:"placeholder",narrative:"The wind dies and the ash settles into an unnatural stillness. Then — faint, just at the edge of hearing — voices. Not speaking to each other. Speaking to you. Each of them in the voice of someone you have lost.",choices:[{text:"Listen and try to understand (Arcana TN 10)",visibleCost:null,skillCheck:{skill:"arcana",stat:"wit",tn:10},outcomes:{success:{text:"You quiet your mind and hear it plainly: the ash preserves echoes of the dead. The voice — your voice, your loss — tells you something. A name. A direction. A truth you didn't know you needed.",effects:[{type:"flag",key:"ash_voices_heard",value:!0},{type:"morale",value:-5},{type:"log",text:"The ash spoke. You listened."}]},failure:{text:"The words dissolve before you grasp them. All that remains is a chill and a deep, sourceless grief.",effects:[{type:"morale",value:-10},{type:"damage",targetRandom:!0,value:2}]}}},{text:"Cover your ears and march through",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You push forward, jaw set. The voices fade. You never know what they would have said.",effects:[{type:"morale",value:-3}]},failure:{text:"",effects:[]}}}],cooldown:7},{id:"abandoned_cart",title:"THE ABANDONED CART",biomes:["ashfields","ironmarch"],weight:12,type:"opportunity",tags:["food_source"],illustration:"placeholder",narrative:"A merchant's cart sits axle-deep in dried mud, one wheel snapped clean off. The horse is gone — dead or fled. The canvas cover is still laced tight. Whatever was being hauled, someone left it behind.",choices:[{text:"Search the cart (Perception TN 7)",visibleCost:null,skillCheck:{skill:"perception",stat:"hed",tn:7},outcomes:{success:{text:"Beneath a false floor you find three sealed jars of preserved grain and a leather case of medicine supplies. Whoever abandoned this cart did it in a hurry.",effects:[{type:"food",value:4},{type:"medicine",value:2},{type:"log",text:"You salvaged food and medicine from an abandoned merchant's cart."}]},failure:{text:"You find only rotted cloth and an empty strongbox. Either someone got here first, or the merchant took everything that mattered.",effects:[{type:"morale",value:-2}]}}},{text:"Take only what's visible and move on",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You take a partial sack of millet from the cart bed — not much, but not nothing.",effects:[{type:"food",value:2}]},failure:{text:"",effects:[]}}},{text:"Leave it — could be a trap",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You give it a wide berth. Caution costs nothing. Probably.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"ash_fever",title:"THE GREY LUNG",biomes:["ashfields"],weight:9,type:"danger",illustration:"placeholder",narrative:"One of your party wakes with grey mucus crusting their lips and a rattling cough that won't stop. The ash gets into everything eventually — the lungs, the blood, the dreams. This is how it starts.",choices:[{text:"Treat them with medicine (–1 Medicine)",visibleCost:"1 medicine",skillCheck:{skill:"medicine",stat:"wit",tn:9},outcomes:{success:{text:"The poultice draws out the ash-congestion. They're pale and weak, but the rattling stops by nightfall. You caught it early enough.",effects:[{type:"medicine",value:-1},{type:"morale",value:5},{type:"log",text:"You treated a case of grey lung before it took hold."}]},failure:{text:"You apply what you know, but it's not enough. They need rest and real medicine, neither of which you have. They march on anyway, grey-faced.",effects:[{type:"medicine",value:-1},{type:"damage",targetRandom:!0,value:6},{type:"morale",value:-5}]}}},{text:"Try nature knowledge to find a remedy (Nature TN 10)",visibleCost:null,skillCheck:{skill:"nature",stat:"hed",tn:10},outcomes:{success:{text:"You find ash-nettle growing in the ditch — bitter but medicinal. The patient chews it for hours and the rattling fades to a whisper.",effects:[{type:"morale",value:3},{type:"log",text:"Ash-nettle kept the grey lung from spreading."}]},failure:{text:"Everything out here is dead or dying. Nothing useful grows in this grey waste.",effects:[{type:"damage",targetRandom:!0,value:4},{type:"morale",value:-6}]}}},{text:"Rest for the day and hope it passes (costs march)",visibleCost:null,skillCheck:null,outcomes:{success:{text:"They rest and sweat through it. By the following morning the worst has passed, though they're hollowed out and exhausted.",effects:[{type:"morale",value:-3},{type:"damage",targetRandom:!0,value:2}]},failure:{text:"",effects:[]}}}],cooldown:3},{id:"standing_stones",title:"THE UNMARKED STONES",biomes:["ashfields","greywood"],weight:6,type:"discovery",illustration:"placeholder",narrative:"Seven standing stones rise from the ash in a perfect circle. They aren't on any map. The ash around them is bone-dry and completely undisturbed — no footprints, no wind-patterns, nothing. At their center, something catches the light.",choices:[{text:"Enter the circle and examine what's inside",visibleCost:null,skillCheck:{skill:"arcana",stat:"wit",tn:9},outcomes:{success:{text:"At the center lies a knife made from a material you've never seen — neither stone nor metal, warm to the touch. Ancient script runs down its length. You take it.",effects:[{type:"item",itemId:"ancient_knife"},{type:"flag",key:"found_standing_stones",value:!0},{type:"morale",value:5},{type:"log",text:"You recovered a strange blade from a circle of standing stones."}]},failure:{text:"The moment you cross the threshold between stones, the world lurches. You stumble out and find an hour has passed that you cannot account for. Your hands are shaking.",effects:[{type:"damage",targetAll:!0,value:3},{type:"morale",value:-8}]}}},{text:"Study the stones from outside (Lore TN 9)",visibleCost:null,skillCheck:{skill:"history",stat:"wit",tn:9},outcomes:{success:{text:"The arrangement matches descriptions of Old Compact boundary markers — places where dead could cross. They're not supposed to still be active.",effects:[{type:"flag",key:"compact_stones_known",value:!0},{type:"morale",value:-5},{type:"log",text:"You identified the stones as Old Compact boundary markers."}]},failure:{text:"You don't recognize the stonework. You note the location and move on.",effects:[]}}},{text:"Mark the location and leave immediately",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Some things are better left undisturbed. You note the stones and put distance between yourself and them.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:10},{id:"child_at_roadside",title:"THE CHILD ALONE",biomes:["ashfields","ironmarch"],weight:6,type:"moral",illustration:"placeholder",narrative:"A child, perhaps seven years old, sits in the middle of the road. She holds a cloth doll. She isn't crying. She has no pack, no food, no visible wounds. She watches your party approach with flat, exhausted eyes.",choices:[{text:"Stop and tend to her (–1 Food, –1 Water)",visibleCost:"1 food, 1 water",skillCheck:{skill:"persuasion",stat:"rch",tn:7},outcomes:{success:{text:"She speaks at last: her village is three hours back, burned two days ago. She's been walking toward the sound of other people. You get her story, share what you can, and point her toward the road south where refugees are moving.",effects:[{type:"food",value:-1},{type:"water",value:-1},{type:"morale",value:10},{type:"flag",key:"helped_the_child",value:!0},{type:"log",text:"You helped a child survivor and sent her south toward safety."}]},failure:{text:"She won't speak, won't move. Eventually you leave food and water beside her and walk on. You tell yourself someone else will find her.",effects:[{type:"food",value:-1},{type:"water",value:-1},{type:"morale",value:-5}]}}},{text:"Keep moving — you cannot carry every tragedy",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You walk past. No one speaks about it for the rest of the day. The silence is its own kind of weight.",effects:[{type:"morale",value:-15}]},failure:{text:"",effects:[]}}}],cooldown:8},{id:"greywood_ambush",title:"THE STILL BRANCHES",biomes:["greywood"],weight:11,type:"danger",illustration:"placeholder",narrative:"The greywood has been too quiet for an hour. No wind. No birds. The grey trees stand like watchers. Then you hear the creak of a bowstring being drawn. Somewhere in the branches above the road, someone has had you in their sights since the last bend.",choices:[{text:"Freeze and call out — negotiate (Persuasion TN 9)",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:9},outcomes:{success:{text:'Your voice carries the right tone — calm, direct, not afraid. A figure drops from the branches: a hollow-eyed hunter in bark-cloth. She was testing you. "You smell like the road, not the iron." She lets you pass and gives you a warning about what lies ahead.',effects:[{type:"flag",key:"woodswoman_met",value:!0},{type:"morale",value:5},{type:"log",text:"A greywood hunter tested you and let you pass, offering a warning."}]},failure:{text:"An arrow splits the air between two party members. Then silence. They wanted you to know they could have killed you — but now they're dropping from the trees. There's no talking your way out.",effects:[{type:"morale",value:-8},{type:"damage",targetRandom:!0,value:3}],leadsToCombat:!0}}},{text:"Take cover immediately (Stealth TN 8)",visibleCost:null,skillCheck:{skill:"stealth",stat:"hed",tn:8},outcomes:{success:{text:"Your party scatters into the undergrowth with surprising discipline. The ambush never triggers — they've lost you. You work around through the brush.",effects:[{type:"morale",value:5}]},failure:{text:"You're in the open when the first arrow comes. It grazes one of yours. They're already moving through the brush — no choice but to fight.",effects:[{type:"damage",targetRandom:!0,value:5},{type:"morale",value:-6}],leadsToCombat:!0}}}],cooldown:4},{id:"greywood_shrine",title:"THE HUNGER SHRINE",biomes:["greywood"],weight:7,type:"exploration",illustration:"placeholder",narrative:"Tucked behind a rotting oak is a shrine that predates the empire. Carved from a single stone, it depicts a figure eating its own hands. Fresh offerings sit before it: a rabbit's foot, two copper coins, a child's tooth. Someone still worships here.",choices:[{text:"Leave an offering (–1 Food)",visibleCost:"1 food",skillCheck:null,outcomes:{success:{text:"You place a portion of rations at the shrine's base. That night, despite everything, you sleep deeper than you have in weeks. You wake with a strange certainty about the road ahead.",effects:[{type:"food",value:-1},{type:"morale",value:8},{type:"flag",key:"hunger_shrine_honored",value:!0}]},failure:{text:"",effects:[]}}},{text:"Take the copper coins (–Morale risk)",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Two copper coins. Barely worth the trouble. Most of the party looks at you differently afterward.",effects:[{type:"gold",value:2},{type:"morale",value:-10},{type:"flag",key:"hunger_shrine_robbed",value:!0}]},failure:{text:"",effects:[]}}},{text:"Observe and move on",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You note the offerings and continue. The greywood keeps its secrets.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"lost_scholar",title:"THE MAP-MAKER",biomes:["greywood","ashfields"],weight:8,type:"social",illustration:"placeholder",narrative:"An elderly man sits on a boulder at a fork in the road, surrounded by unrolled maps he's clearly made himself. He's been crying, though he's composed himself by the time you approach. His cart horse is dead in the ditch. He has nowhere to go.",choices:[{text:"Trade for his maps (–5 Gold)",visibleCost:"5 gold",skillCheck:null,outcomes:{success:{text:"His maps are extraordinary — three decades of survey work in the eastern territories. He names fair prices for each and seems grateful someone wants them. Among them is a detailed survey of the Hollows that no one living has apparently updated in years.",effects:[{type:"gold",value:-5},{type:"flag",key:"hollows_survey_acquired",value:!0},{type:"morale",value:5},{type:"log",text:"You purchased a decades-old survey of the Hollows from a stranded map-maker."}]},failure:{text:"",effects:[]}}},{text:"Share food and hear his story (–1 Food)",visibleCost:"1 food",skillCheck:{skill:"persuasion",stat:"rch",tn:6},outcomes:{success:{text:"Over a shared meal he tells you about three villages ahead that are still occupied, still trading. He sketches you a rough note. It's worth more than coin.",effects:[{type:"food",value:-1},{type:"flag",key:"scholar_road_notes",value:!0},{type:"morale",value:6}]},failure:{text:"He's too lost in his own grief to be useful. You share the food anyway. He weeps quietly.",effects:[{type:"food",value:-1},{type:"morale",value:-2}]}}},{text:"Keep walking",visibleCost:null,skillCheck:null,outcomes:{success:{text:"There are too many like him on the roads. You cannot carry them all.",effects:[{type:"morale",value:-5}]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"greywood_sickness",title:"THE ROT IN THE WATER",biomes:["greywood"],weight:9,type:"danger",illustration:"placeholder",narrative:"The stream looked clear. Tasted fine. But three hours later half the party is doubled over, and the pain is spreading. The greywood water runs through root-rot and old graves. You should have boiled it.",choices:[{text:"Treat with medicine (–2 Medicine)",visibleCost:"2 medicine",skillCheck:{skill:"medicine",stat:"wit",tn:8},outcomes:{success:{text:"The purgative works quickly, unpleasantly, and completely. The affected are wretched for two hours and then recover. You make a note: boil everything.",effects:[{type:"medicine",value:-2},{type:"morale",value:-3},{type:"log",text:"Root-rot sickness treated before it spread."}]},failure:{text:"You try your best but the dose is wrong or the timing is off. The sickness progresses through the night.",effects:[{type:"medicine",value:-2},{type:"damage",targetAll:!0,value:4},{type:"morale",value:-8}]}}},{text:"Wait it out — rest and water only",visibleCost:null,skillCheck:null,outcomes:{success:{text:"A brutal day and night of rest. By morning they're hollow-cheeked but walking. You've lost time but kept your medicine for something worse.",effects:[{type:"damage",targetAll:!0,value:3},{type:"morale",value:-6}]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"salt_mirage",title:"THE CITY IN THE GLASS",biomes:["salt_flats"],weight:8,type:"exploration",illustration:"placeholder",narrative:"The heat shimmer on the flats assembles itself into the skyline of a city: towers, gates, the smoke of industry. It's completely convincing for nearly an hour. Then two party members start walking toward it without speaking.",choices:[{text:"Stop them before they wander (Persuasion TN 8)",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:8},outcomes:{success:{text:"You grab them and hold on. When they come back to themselves they're shaking. The mirage dissolves. You push on, staying in physical contact with each other.",effects:[{type:"morale",value:-5},{type:"log",text:"The salt flat mirages nearly took two of your party."}]},failure:{text:"You get one back before the other is twenty yards into the flats. You bring them both back but lose hours of travel and two of your water supply to the chase.",effects:[{type:"water",value:-2},{type:"morale",value:-10},{type:"damage",targetRandom:!0,value:4}]}}},{text:"You're also entranced — roll Will (Wil TN 9)",visibleCost:null,skillCheck:{skill:"survival",stat:"wil",tn:9},outcomes:{success:{text:"Something in you resists the pull. You watch your companions start to drift and tackle them both before the flats claim them.",effects:[{type:"morale",value:5}]},failure:{text:"You come to your senses half a mile from the road with no clear memory of walking here. Everyone is shaken. The water you used following each other back is gone.",effects:[{type:"water",value:-3},{type:"damage",targetAll:!0,value:3},{type:"morale",value:-12}]}}}],cooldown:5},{id:"salt_cache",title:"THE BURIED CACHE",biomes:["salt_flats"],weight:10,type:"opportunity",tags:["food_source","water_source"],illustration:"placeholder",narrative:"A cairn of white stones marks something deliberately buried. Salt flat travelers sometimes cache supplies for the return trip. Whoever left this never came back for it — the stones haven't been moved in months, maybe years.",choices:[{text:"Dig it up (Survival TN 6)",visibleCost:null,skillCheck:{skill:"survival",stat:"hed",tn:6},outcomes:{success:{text:'The cache is sealed in oil-treated leather: six days of dried rations, a full waterskin, and a journal whose last entry is just a name and the word "forgive." You take the supplies.',effects:[{type:"food",value:6},{type:"water",value:3},{type:"morale",value:-3},{type:"log",text:"You found a years-old supply cache on the salt flats."}]},failure:{text:"You dig for an hour. The cache is too deep or it's been moved. The salt has fooled you — the cairn is just a grave marker.",effects:[{type:"morale",value:-5}]}}},{text:"Leave it for whoever needs it more",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You replace the stones and move on. The salt flats are full of burials. At least this one has something to give.",effects:[{type:"morale",value:3}]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"salt_traders",title:"THE SALT CARAVAN",biomes:["salt_flats"],weight:9,type:"social",illustration:"placeholder",narrative:"A small caravan of four carts plods across the flats heading west. They're moving slower than they should. When you draw close you can see why: two of their draft animals are lame, and the people driving them look barely more functional.",choices:[{text:"Trade provisions (–3 Food for +8 Gold)",visibleCost:"3 food",skillCheck:{skill:"trade",stat:"rch",tn:7},outcomes:{success:{text:"They're desperate enough to pay well for food they can't spare. The lead trader counts out silver with practiced hands and thanks you in a language you half-recognize. It's good trade for both of you.",effects:[{type:"food",value:-3},{type:"gold",value:8},{type:"morale",value:3}]},failure:{text:"The trade sours over the price. You part on cold terms with less food and no silver.",effects:[{type:"food",value:-1},{type:"morale",value:-3}]}}},{text:"Help treat the lame animals (Animal Handling TN 8)",visibleCost:null,skillCheck:{skill:"animal_handling",stat:"rch",tn:8},outcomes:{success:{text:"You reset the shoe that was causing the lameness and pack the hoof properly. The caravan master is openly moved. She insists you take a wheel of hard cheese and a detailed account of a bandit camp two days west.",effects:[{type:"food",value:3},{type:"flag",key:"bandit_camp_known",value:!0},{type:"morale",value:8},{type:"log",text:"You helped a salt caravan and learned of a bandit camp to the west."}]},failure:{text:"You try but the injury is beyond your knowledge to treat on the road. They thank you for trying. Everyone parts company in quiet sadness.",effects:[{type:"morale",value:-2}]}}},{text:"Keep moving",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You wave as you pass. They don't wave back. They have enough of their own problems.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"imperial_patrol",title:"THE IRON PATROL",biomes:["ironmarch"],weight:11,type:"social",illustration:"placeholder",narrative:"Six soldiers in dented imperial livery block the road ahead. Their officer examines you with the practiced suspicion of a man who has learned to find enemies everywhere. His hand rests on his sword pommel. He wants papers you probably don't have.",choices:[{text:"Produce documentation or bluff (Deception TN 9)",visibleCost:null,skillCheck:{skill:"deception",stat:"wit",tn:9},outcomes:{success:{text:"Whatever you produce or invent, you sell it well. The officer examines it, nods stiffly, and stands aside. His soldiers relax. You walk through with your hearts hammering.",effects:[{type:"morale",value:5},{type:"log",text:"You talked your way past an imperial patrol."}]},failure:{text:"He doesn't believe you. The soldiers surround your party — swords half-drawn. Someone in your group reaches for a weapon and the situation ignites.",effects:[{type:"gold",value:-10},{type:"morale",value:-10},{type:"damage",targetRandom:!0,value:2}],leadsToCombat:!0}}},{text:"Pay the unofficial toll (–8 Gold)",visibleCost:"8 gold",skillCheck:null,outcomes:{success:{text:"Coin speaks plainer than papers. The officer pockets it without a word and jerks his head. You pass without incident.",effects:[{type:"gold",value:-8},{type:"morale",value:-3}]},failure:{text:"",effects:[]}}},{text:"Detour around them (Navigation TN 8)",visibleCost:null,skillCheck:{skill:"navigation",stat:"hed",tn:8},outcomes:{success:{text:"You spot a dry gully running parallel to the road. Three hours of hard walking gets you clear of them with no encounter.",effects:[{type:"morale",value:3}]},failure:{text:"You wander for five hours and emerge on the road two miles behind where you started. The patrol has moved on, but you've lost a day.",effects:[{type:"morale",value:-6},{type:"food",value:-1},{type:"water",value:-1}]}}}],cooldown:3},{id:"fort_ruins",title:"THE GUTTED FORT",biomes:["ironmarch"],weight:8,type:"opportunity",tags:["food_source"],illustration:"placeholder",narrative:"An imperial wayfort stands cracked and gutted beside the road. Its gate is gone; its garrison long dead or fled. But the old supply rooms are built into stone foundations that fire and looting can't fully reach. Someone already cleared it once, but that was months ago.",choices:[{text:"Search the ruins thoroughly (Perception TN 8)",visibleCost:null,skillCheck:{skill:"perception",stat:"hed",tn:8},outcomes:{success:{text:"Behind a collapsed wall you find a sealed alcove: imperial campaign rations, still edible, three medicinal kit rolls, and — most usefully — a marked tactical map of the region that predates the collapse.",effects:[{type:"food",value:5},{type:"medicine",value:3},{type:"flag",key:"imperial_map_acquired",value:!0},{type:"log",text:"You found a hidden imperial supply cache in the gutted fort."}]},failure:{text:"You find only ash and boot-leather. The looters were thorough. You spend an hour confirming what you suspected: there's nothing left worth having.",effects:[{type:"morale",value:-3}]}}},{text:"Make camp here for the night (safe shelter)",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Stone walls keep the ash-wind out. The party sleeps better than they have in days. Wounds close a little. The stone feels almost safe.",effects:[{type:"heal",targetAll:!0,value:3},{type:"morale",value:6}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"wounded_merchant",title:"THE MERCHANT ON THE ROAD",biomes:["ironmarch","ashfields"],weight:9,type:"moral",illustration:"placeholder",narrative:"A stout woman lies at the roadside with a crossbow bolt through her thigh. Her pack mule stands nearby, loaded with sealed crates. She's conscious, pale, and watching you approach with the calculating look of someone who's been robbed before.",choices:[{text:"Treat her wound (–1 Medicine, Medicine TN 7)",visibleCost:"1 medicine",skillCheck:{skill:"medicine",stat:"wit",tn:7},outcomes:{success:{text:"You extract the bolt cleanly and bind the wound. She's going to limp for weeks but she'll walk. In payment she opens one of her crates and gives you supplies worth more than what you spent.",effects:[{type:"medicine",value:-1},{type:"food",value:3},{type:"gold",value:12},{type:"morale",value:8},{type:"log",text:"You saved a wounded merchant who paid you in goods and coin."}]},failure:{text:"You try but the bolt is seated badly and you make things worse. She bears it without screaming but you both know. She thanks you anyway. There's nothing more you can do.",effects:[{type:"medicine",value:-1},{type:"damage",targetRandom:!0,value:2},{type:"morale",value:-5}]}}},{text:"Rob her while she's helpless",visibleCost:null,skillCheck:null,outcomes:{success:{text:`She watches you take her supplies with eyes that don't blink. "Remember my face," she says. You probably will. The supplies are worth something. The party knows exactly what you are now.`,effects:[{type:"food",value:5},{type:"gold",value:15},{type:"morale",value:-20},{type:"flag",key:"robbed_the_merchant",value:!0}]},failure:{text:"",effects:[]}}},{text:"Leave water and wish her well",visibleCost:"1 water",skillCheck:null,outcomes:{success:{text:`It's not enough but it's something. She takes the water and nods. "There's a healer at Vance's Crossing, three leagues on," she tells you. Worth knowing.`,effects:[{type:"water",value:-1},{type:"flag",key:"vances_crossing_known",value:!0},{type:"morale",value:3}]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"hollow_whisper",title:"THE HOLLOW SPEAKS",biomes:["hollows"],weight:8,type:"exploration",illustration:"placeholder",narrative:"The hollows are deep and lightless by midday. Something has been following you for two hours — not footsteps, more like the sound of breathing just behind your left ear. When you stop, it stops. When you turn, there is nothing there.",choices:[{text:"Address it directly (Arcana TN 10)",visibleCost:null,skillCheck:{skill:"arcana",stat:"wit",tn:10},outcomes:{success:{text:"You speak to it by the old protocols. It responds — not in words, but in sensation: a cold pressure that resolves into direction. It's guiding you away from a path collapse ahead.",effects:[{type:"flag",key:"hollow_guide_followed",value:!0},{type:"morale",value:5},{type:"log",text:"A hollow presence warned you away from a path collapse."}]},failure:{text:"You say the wrong thing or say it wrong. The presence becomes hostile — cold that reaches the bone, and two of your party begin bleeding from the nose.",effects:[{type:"damage",targetAll:!0,value:5},{type:"morale",value:-12}]}}},{text:"Maintain your pace and ignore it (Wil TN 9)",visibleCost:null,skillCheck:{skill:"survival",stat:"wil",tn:9},outcomes:{success:{text:"You keep your eyes forward and your breathing steady. Slowly — over the course of an hour — it stops following. Whatever it wanted, you denied it.",effects:[{type:"morale",value:-5}]},failure:{text:"One of your party breaks and runs. You spend an hour finding them, shaking and incoherent, curled against a tree trunk. They don't speak about it.",effects:[{type:"morale",value:-15},{type:"damage",targetRandom:!0,value:4}]}}}],cooldown:4},{id:"hollow_village",title:"THE EMPTY VILLAGE",biomes:["hollows"],weight:7,type:"discovery",tags:["food_source"],illustration:"placeholder",narrative:"Eight stone cottages arranged around a dry well. No sign of violence, no sign of fire, no bodies. Just emptiness — doors left open, meals rotted on tables, a dog lying dead of old age on the threshold of the largest house. They simply left.",choices:[{text:"Search each house for supplies (Nature TN 7)",visibleCost:null,skillCheck:{skill:"nature",stat:"hed",tn:7},outcomes:{success:{text:"Root cellars sealed against frost: dried vegetables, salted pork, two crocks of rendered lard. The village fed itself well until whatever happened, happened. You take what you can carry.",effects:[{type:"food",value:6},{type:"morale",value:-3},{type:"log",text:"You salvaged six days of food from an abandoned hollow village."}]},failure:{text:"The cellars have been flooded or collapsed. What food remained has rotted completely. The village yields nothing but damp and unease.",effects:[{type:"morale",value:-6}]}}},{text:"Look for signs of what happened (Lore TN 9)",visibleCost:null,skillCheck:{skill:"history",stat:"wit",tn:9},outcomes:{success:{text:`In the headman's house you find a ledger with the last entry circled twice: "The Compact closed the sixth gate. We have been given to the deep." Whatever that means, it means this village was not abandoned — it was surrendered.`,effects:[{type:"flag",key:"compact_gate_known",value:!0},{type:"morale",value:-8},{type:"log",text:"You learned the hollow village was surrendered to the deep by the Compact."}]},failure:{text:"You find no clear answer. A village full of small tragedies and no conclusions. You move on unsatisfied.",effects:[{type:"morale",value:-5}]}}},{text:"Camp here and rest (shelter)",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Solid roofs and real walls. You sleep in beds for the first time in weeks, even if they belong to the absent. You try not to think about that.",effects:[{type:"heal",targetAll:!0,value:4},{type:"morale",value:3}]},failure:{text:"",effects:[]}}}],cooldown:8},{id:"hollow_rockfall",title:"THE FALLING STONE",biomes:["hollows"],weight:10,type:"danger",illustration:"placeholder",narrative:"The hollow walls narrow here and the path runs directly below a shelf of limestone that hasn't been maintained since the empire built the road. A low rumble. Then a crack. Then the sound of falling stone.",choices:[{text:"Run — get clear of the zone (Survival TN 8)",visibleCost:null,skillCheck:{skill:"survival",stat:"hed",tn:8},outcomes:{success:{text:"You've been watching the walls. Your shout gets everyone moving in the right direction. The rockfall blocks the path behind you in a cloud of white dust. You're shaken but whole.",effects:[{type:"morale",value:5},{type:"log",text:"You escaped a rockfall with quick thinking."}]},failure:{text:"Not everyone gets clear in time. One party member takes the edge of the slide — bruised, bleeding, possibly with a cracked rib.",effects:[{type:"damage",targetRandom:!0,value:8},{type:"morale",value:-8}]}}},{text:"Brace and shield each other",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:9},outcomes:{success:{text:"You lock together under packs and shields. Stones bounce off you. The pain is real but nothing breaks. You emerge battered and covered in dust, still standing.",effects:[{type:"damage",targetAll:!0,value:2},{type:"morale",value:8}]},failure:{text:"The formation breaks and the fall scatters the party. When the dust clears you're bleeding and separated. It takes an hour to regroup.",effects:[{type:"damage",targetAll:!0,value:6},{type:"morale",value:-10}]}}}],cooldown:3},{id:"hermit_warning",title:"THE HERMIT BY THE FIRE",biomes:["ashfields","greywood","hollows"],weight:7,type:"social",illustration:"placeholder",narrative:"A small fire burns beside the road — too small to keep warm by, large enough to be seen. An old man sits feeding it twigs with the patience of someone who has nothing else to do. He watches your approach without moving. He has been waiting, or he has simply stopped caring about the difference.",choices:[{text:"Sit with him and listen (–1 Food, Perception TN 7)",visibleCost:"1 food",skillCheck:{skill:"perception",stat:"hed",tn:7},outcomes:{success:{text:"He speaks in fragments — old information, half-remembered — but there's gold in it. He describes a collapsed bridge three days ahead and the ford that's replaced it, where bandits now collect passage.",effects:[{type:"food",value:-1},{type:"flag",key:"met_hermit",value:!0},{type:"flag",key:"bridge_ford_known",value:!0},{type:"morale",value:3},{type:"log",text:"The hermit told you of a ford guarded by bandits ahead."}]},failure:{text:"He talks for an hour about things you cannot decode — old names, old places, old grievances. You leave fed but none the wiser.",effects:[{type:"food",value:-1},{type:"morale",value:-2}]}}},{text:"Trade him something for information (–3 Gold)",visibleCost:"3 gold",skillCheck:null,outcomes:{success:{text:"Gold he'll take, but it's the offer of respect that loosens his tongue. He tells you about a ruined farmstead a half-day north that still has grain in its underground storage — if the ash hasn't gotten to it.",effects:[{type:"gold",value:-3},{type:"flag",key:"farmstead_cache_known",value:!0},{type:"morale",value:3}]},failure:{text:"",effects:[]}}},{text:"Keep walking",visibleCost:null,skillCheck:null,outcomes:{success:{text:"He watches you pass and says nothing. You feel his eyes on you until you round the bend.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:7},{id:"disease_outbreak",title:"THE CAMP PLAGUE",biomes:["ashfields","ironmarch","hollows"],weight:8,type:"danger",illustration:"placeholder",narrative:"A dozen refugees camp at the roadside. They wave you down with both arms — and then you see the rest of the camp: half of them are lying down, skin mottled, breathing wrong. Someone has marked the camp boundary with white rag tied to stakes. They know what this is.",choices:[{text:"Help with medicine (–3 Medicine, Medicine TN 10)",visibleCost:"3 medicine",skillCheck:{skill:"medicine",stat:"wit",tn:10},outcomes:{success:{text:"You work through the night. Some will still die — the ones too far gone — but you stop the progression in the others. By morning, the camp leader presses into your hands everything they have to give: a small cache of food and a sealed letter of introduction to a settlement three days east.",effects:[{type:"medicine",value:-3},{type:"food",value:4},{type:"flag",key:"refugee_camp_aided",value:!0},{type:"morale",value:10},{type:"log",text:"You treated a camp plague and earned a letter of introduction."}]},failure:{text:"You do what you can but it's not enough. You leave diminished — in supplies, in hope, and carrying the particular guilt of the person who tried and failed.",effects:[{type:"medicine",value:-3},{type:"morale",value:-12},{type:"damage",targetRandom:!0,value:3}]}}},{text:"Leave supplies at the boundary and move on (–2 Food, –1 Medicine)",visibleCost:"2 food, 1 medicine",skillCheck:null,outcomes:{success:{text:"You leave what you can at the white-rag boundary without crossing it. It's not enough but it's something, and you don't compromise your party. The camp leader nods slowly from fifty feet away.",effects:[{type:"food",value:-2},{type:"medicine",value:-1},{type:"morale",value:-5}]},failure:{text:"",effects:[]}}},{text:"Give the camp a wide berth",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You circle through the undergrowth and rejoin the road past the camp. The right call, possibly. Still hard to watch.",effects:[{type:"morale",value:-8}]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"ruined_farmstead",title:"THE GREY FARMSTEAD",biomes:["ashfields","ironmarch"],weight:9,type:"opportunity",tags:["food_source"],illustration:"placeholder",narrative:"A farmstead sits half-collapsed beside the road, the thatch burned long ago and the fields long grey. But the stone outbuilding still stands, its doors sealed. These people planned for the end — they just didn't survive long enough to use the plan.",choices:[{text:"Break open the outbuilding (Crafting TN 7)",visibleCost:null,skillCheck:{skill:"crafting",stat:"wit",tn:7},outcomes:{success:{text:`Inside: grain jars stoppered in wax, dried meat on hooks, and a sealed cask of something that smells like weak wine but won't kill you. The family even left a note: "For whoever finds this. May you make better use of it than we did."`,effects:[{type:"food",value:7},{type:"morale",value:5},{type:"log",text:"You found a carefully stocked farmstead cache left for strangers."}]},failure:{text:"The lock defeats you. The building is more solidly made than it looks. You spend an hour and walk away empty-handed.",effects:[{type:"morale",value:-4}]}}},{text:"Search the farmhouse ruins (Nature TN 6)",visibleCost:null,skillCheck:{skill:"nature",stat:"hed",tn:6},outcomes:{success:{text:"The root cellar beneath the collapsed floor still holds dried tubers and a crock of pickled vegetables. Not much, but it's real food.",effects:[{type:"food",value:3}]},failure:{text:"Ash and rot. Whatever was here has been consumed by time or looters or both.",effects:[{type:"morale",value:-2}]}}}],cooldown:5},{id:"false_guide",title:"THE HELPFUL STRANGER",biomes:["ironmarch","salt_flats"],weight:7,type:"danger",illustration:"placeholder",narrative:"A cheerful man in a battered hat falls into step beside your party. He knows the road well, he says — the shortcuts, the safe water. He volunteers to guide you to the next waypoint. He asks for nothing. He's been pleasant for two hours.",choices:[{text:"Read his intentions (Perception TN 9)",visibleCost:null,skillCheck:{skill:"perception",stat:"hed",tn:9},outcomes:{success:{text:"He's been guiding you slightly north for an hour. The shortcut he offered would have taken you through a hollow where his friends are waiting. You turn the tables: you stop, address him by the wrong name, and watch his face. He bolts. You find the hollow on your own — and avoid it.",effects:[{type:"flag",key:"false_guide_exposed",value:!0},{type:"morale",value:8},{type:"log",text:"You exposed a false guide before he could lead you into ambush."}]},failure:{text:"He's good at being liked. When the ambush springs at the hollow, your party is scattered and unprepared. The bandits want more than gold.",effects:[{type:"damage",targetAll:!0,value:5},{type:"gold",value:-8},{type:"morale",value:-12}],leadsToCombat:!0}}},{text:"Trust but watch him carefully (Persuasion TN 8)",visibleCost:null,skillCheck:{skill:"intimidation",stat:"grt",tn:8},outcomes:{success:{text:'You let him know — quietly and specifically — what will happen if his guidance proves false. He blinks once, reconsiders something, and the "shortcut" he was planning never comes up. He parts ways at the next junction, suddenly recalled elsewhere.',effects:[{type:"morale",value:3}]},failure:{text:"He smiles at your warning and walks a little faster. The ambush at the hollow is moderately successful — they weren't expecting you to fight back. Steel is drawn.",effects:[{type:"damage",targetAll:!0,value:3},{type:"gold",value:-5},{type:"morale",value:-8}],leadsToCombat:!0}}}],cooldown:5},{id:"old_battlefield",title:"THE IRON ROAD DEAD",biomes:["ironmarch","ashfields"],weight:8,type:"discovery",tags:["food_source"],illustration:"placeholder",narrative:"The road runs through a field of old battle dead — imperial soldiers and their enemies, too weathered now to tell apart, half-buried in the dust. No one collected them. No one buried them properly. Crows still pick at bones that are years old.",choices:[{text:"Search for salvageable equipment (Trade TN 7)",visibleCost:null,skillCheck:{skill:"trade",stat:"rch",tn:7},outcomes:{success:{text:"Most of it is useless rust, but a soldier's sealed pack has been sheltered beneath a body and contains campaign rations — the hard, dense biscuit that keeps forever — and a coin purse.",effects:[{type:"food",value:3},{type:"gold",value:6},{type:"morale",value:-5},{type:"log",text:"You salvaged supplies from the Iron Road battlefield dead."}]},failure:{text:"Everything was stripped long ago. You move through quickly, stepping around the dead, saying nothing.",effects:[{type:"morale",value:-8}]}}},{text:"Say words over the dead (Lore TN 6)",visibleCost:null,skillCheck:{skill:"history",stat:"wit",tn:6},outcomes:{success:{text:"You know the old words — or enough of them. The party listens. It doesn't fix anything, but it's the right thing to do, and the party feels it.",effects:[{type:"morale",value:8},{type:"flag",key:"honored_battle_dead",value:!0}]},failure:{text:"You try to remember the rites and can't. You stand in silence for a moment instead. It's something.",effects:[{type:"morale",value:2}]}}},{text:"Move through quickly and say nothing",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You keep your eyes on the road and your mouths shut. The field falls behind you.",effects:[{type:"morale",value:-5}]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"avalanche_warning",title:"THE RUMBLING ABOVE",biomes:["mountains"],weight:9,type:"danger",illustration:"placeholder",narrative:'A deep, resonant groan rolls through the peaks above you. Then another. The snow shelf overhanging the pass has been building for weeks and the morning thaw is doing its work. A local guide post carved in stone beside the trail reads: "Turn back if the mountain speaks." The mountain is speaking.',choices:[{text:"Sprint through the danger zone (Survival TN 9)",visibleCost:null,skillCheck:{skill:"survival",stat:"hed",tn:9},outcomes:{success:{text:"You read the shelf correctly — the instability is at the far end of the choke, not the near. You move fast and low, single file, and clear the exposed stretch as a curtain of white comes down behind you. Close. Very close.",effects:[{type:"morale",value:5},{type:"log",text:"You outran an avalanche through the mountain pass."}]},failure:{text:"You're halfway through when the shelf lets go. The wave of snow and ice hits like a wall. Two members are buried to the waist and must be dug out. No one dies, but it costs everything you have.",effects:[{type:"damage",targetAll:!0,value:5},{type:"morale",value:-10},{type:"water",value:-1}]}}},{text:"Find the safe route around (Navigation TN 9)",visibleCost:null,skillCheck:{skill:"navigation",stat:"hed",tn:9},outcomes:{success:{text:"An old goat trail switchbacks above the danger zone. Hard climbing but safe ground. You emerge two hours later on the far side of the pass, muscles burning, relieved.",effects:[{type:"morale",value:3},{type:"food",value:-1},{type:"log",text:"You found a safe goat trail around the avalanche zone."}]},failure:{text:"The alternate route cliffs out above a ravine. You backtrack, losing half a day, and take the main pass in the late afternoon — the worst time. You get through, but the mountain groans the whole way.",effects:[{type:"food",value:-1},{type:"water",value:-1},{type:"morale",value:-7}]}}},{text:"Wait it out until the shelf settles",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You camp in the lee of a boulder and wait. After four hours the rumbling stops. The pass is buried knee-deep but passable. You lose the day but keep your lives.",effects:[{type:"food",value:-1},{type:"water",value:-1},{type:"morale",value:-4}]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"injured_climber",title:"THE LEDGE BELOW",biomes:["mountains"],weight:7,type:"moral",illustration:"placeholder",narrative:"A shout from below the trail — a young man has fallen to a ledge twelve feet down, his leg bent wrong, his pack still tangled in the rope that stopped his fall. The rope is still attached to a piton you can see in the cliff face. He's alive, barely keeping his composure, staring up at you.",choices:[{text:"Rig a rescue line and bring him up (Athletics TN 8)",visibleCost:null,skillCheck:{skill:"athletics",stat:"grt",tn:8},outcomes:{success:{text:"It takes three of you working together, burning rope and sweat. He comes up pale and biting back screams. His pack holds mountain medicine and three days of high-altitude rations — real food up here. He insists you take it.",effects:[{type:"food",value:3},{type:"medicine",value:2},{type:"morale",value:12},{type:"flag",key:"rescued_climber",value:!0},{type:"log",text:"You rescued an injured climber from a ledge. He gave you his supplies in thanks."}]},failure:{text:"The rope slips and he takes a hard swing against the rock face before you get him stabilized. He makes it up, but the leg is worse. You splint it with what you have. He has nothing left to give and nowhere to go.",effects:[{type:"morale",value:-5},{type:"medicine",value:-1}]}}},{text:"Treat him from above — lower medicine (–1 Medicine)",visibleCost:"1 medicine",skillCheck:null,outcomes:{success:{text:`You lower the kit on a cord and talk him through the splint. He's resourceful. By the time you continue he's propped against the cliff with enough to last until help can reach him. "Keep east," he calls up. "The pass clears by midday."`,effects:[{type:"medicine",value:-1},{type:"morale",value:6},{type:"flag",key:"midday_pass_advice",value:!0}]},failure:{text:"",effects:[]}}},{text:"You cannot carry him — leave and send help from the next settlement",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You shout down the plan and see him nod. Whether help actually arrives is not something you can control. The party moves on through guilt that doesn't ease.",effects:[{type:"morale",value:-12}]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"abandoned_monastery",title:"THE SILENT CLOISTER",biomes:["mountains"],weight:6,type:"exploration",illustration:"placeholder",narrative:"Carved into the mountain's shoulder, a monastery squats behind a collapsed gate. The order that built it is gone — the chapel is open to the sky, the cells empty. But the storage vaults beneath the floor are sealed in old imperial stone, and the scriptorium still has books.",choices:[{text:"Search the vaults (Crafting TN 8)",visibleCost:null,skillCheck:{skill:"crafting",stat:"wit",tn:8},outcomes:{success:{text:"The vaults hold oil — lantern fuel in ceramic jars sealed with wax, and dried herbs still fragrant after years of cold mountain air. The monks prepared for long winters. You fill your containers.",effects:[{type:"fuel",value:4},{type:"medicine",value:2},{type:"log",text:"You found lamp oil and herbs in an abandoned mountain monastery."}]},failure:{text:"The vault door has rusted shut and your tools aren't equal to it. You leave the sealed abundance behind.",effects:[{type:"morale",value:-4}]}}},{text:"Study the scriptorium (Lore TN 9)",visibleCost:null,skillCheck:{skill:"history",stat:"wit",tn:9},outcomes:{success:{text:"A journal in the abbot's hand, dated three years before the collapse. He writes of a route through the Ridgespine that bypasses the worst of the cinderwaste — a passage that isn't on any road map you've seen.",effects:[{type:"flag",key:"monastery_route_known",value:!0},{type:"morale",value:5},{type:"log",text:"You found an abbot's journal describing a secret pass through the Ridgespine."}]},failure:{text:"The books are water-damaged beyond reading. You salvage nothing but a headache and cold hands.",effects:[{type:"morale",value:-3}]}}},{text:"Rest in the sheltered cells overnight",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Stone walls and a stone floor but no wind. The mountain cold stays outside. You sleep hard and wake less broken than you have been in days.",effects:[{type:"heal",targetAll:!0,value:4},{type:"morale",value:7}]},failure:{text:"",effects:[]}}}],cooldown:8},{id:"wisp_lights",title:"THE WALKING LIGHTS",biomes:["fens"],weight:9,type:"exploration",illustration:"placeholder",narrative:"Dusk falls and the fens come alive with blue-white lights, drifting low over the water between the sedge tussocks. They move with a strange purposefulness — circling, retreating, approaching. Three party members have already taken half a step toward the nearest one.",choices:[{text:"Follow a wisp to see where it leads (Arcana TN 9)",visibleCost:null,skillCheck:{skill:"arcana",stat:"wit",tn:9},outcomes:{success:{text:"You follow deliberately, keeping solid ground underfoot, reading the wisp's behavior as a naturalist would. It leads you to a moss-covered cache box sunk in the shallows — an old trapper's store. The wisp dims and vanishes once you find it.",effects:[{type:"food",value:3},{type:"fuel",value:2},{type:"flag",key:"wisp_followed",value:!0},{type:"morale",value:5},{type:"log",text:"A will-o-wisp led you to a trapper's cache in the fens."}]},failure:{text:"The light leads you deeper into the fen and then vanishes. You're knee-deep in black water with no clear path back. It takes two hours and costs real health to find solid ground again.",effects:[{type:"damage",targetAll:!0,value:4},{type:"water",value:-1},{type:"morale",value:-10}]}}},{text:"Drive the lights back (Lore TN 8)",visibleCost:null,skillCheck:{skill:"history",stat:"wit",tn:8},outcomes:{success:{text:"You recall the marsh-word — a sound more than a word, pitched at the back of the throat. The lights retreat to a respectful distance and stay there, escorting you like cold lanterns until you clear the fen.",effects:[{type:"morale",value:6},{type:"log",text:"You spoke the marsh-word and the wisps kept respectful distance."}]},failure:{text:"The sound you make only seems to attract more lights. You lose an hour keeping the fascinated members of your party from wading into the black water.",effects:[{type:"morale",value:-6},{type:"water",value:-1}]}}},{text:"Tether the party together and press through",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You link arms and keep moving, eyes on solid ground, ignoring the lights that dance at your periphery. It costs nerve but nothing else. They fade when you leave the worst of the fen.",effects:[{type:"morale",value:-4}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"fever_marsh",title:"THE WET HEAT",biomes:["fens"],weight:11,type:"danger",illustration:"placeholder",narrative:"The fen fever comes on fast in the worst patches of the marsh — a heat behind the eyes, then chills that don't match the cold, then the joint-ache that means it's already in the blood. One of your party sits down on a hummock and cannot get back up.",choices:[{text:"Treat with medicine now before it spreads (–2 Medicine, Medicine TN 9)",visibleCost:"2 medicine",skillCheck:{skill:"medicine",stat:"wit",tn:9},outcomes:{success:{text:"You know this fever. The bark tincture works if you catch it in the first twelve hours and you have. The patient sweats through the night under close watch and wakes functional, hollow-eyed but walking.",effects:[{type:"medicine",value:-2},{type:"morale",value:5},{type:"log",text:"You broke a case of fen fever in the first twelve hours."}]},failure:{text:"The tincture isn't enough or the dosage is off. The fever digs in. Your patient needs three days they don't have.",effects:[{type:"medicine",value:-2},{type:"damage",targetRandom:!0,value:8},{type:"morale",value:-8}]}}},{text:"Try to forage fen-medicines (Nature TN 11)",visibleCost:null,skillCheck:{skill:"nature",stat:"hed",tn:11},outcomes:{success:{text:"Blackroot grows in the margins of the worst fen patches — bitter and hard to find, but a specific for marsh fever when boiled. You find enough. They recover in two days instead of a week.",effects:[{type:"morale",value:5},{type:"flag",key:"fen_herbalism_known",value:!0},{type:"log",text:"You found blackroot in the fen and cured the marsh fever."}]},failure:{text:"Everything you pick is the wrong plant. The fever runs its course the hard way — five grinding days that cost more than you can say.",effects:[{type:"damage",targetRandom:!0,value:6},{type:"morale",value:-12},{type:"food",value:-2}]}}}],cooldown:4},{id:"sunken_shrine",title:"THE DROWNED ALTAR",biomes:["fens"],weight:6,type:"discovery",illustration:"placeholder",narrative:"Half a metre of black water covers the floor of what was once a shrine — you can see the carved altar stone beneath, and the votive niches in the walls still hold offerings too waterlogged to rot. The water is perfectly still. Something about the quality of light here is wrong in a way that is not unpleasant.",choices:[{text:"Wade in and examine the altar (Arcana TN 9)",visibleCost:null,skillCheck:{skill:"arcana",stat:"wit",tn:9},outcomes:{success:{text:"The altar script is pre-empire, dedicated to the marshland dead. The ritual marks indicate this is a place of safe passage — the dead here do not follow the living out. You place a coin in a niche. Something lightens in the party.",effects:[{type:"morale",value:10},{type:"gold",value:-1},{type:"flag",key:"drowned_altar_blessed",value:!0},{type:"log",text:"You found and honored the drowned altar in the fens. The marsh seems quieter after."}]},failure:{text:"The water is deeper than it looks. You go under once, gasp, and pull back to the threshold. The shrine keeps its secrets.",effects:[{type:"damage",targetRandom:!0,value:3},{type:"morale",value:-4}]}}},{text:"Take what offerings you can reach",visibleCost:null,skillCheck:null,outcomes:{success:{text:"The niches hold coins — old ones, possibly silver under the green. Four of them. The water goes dark as you take them, the light quality changing to something actively hostile. You leave quickly.",effects:[{type:"gold",value:4},{type:"morale",value:-8},{type:"flag",key:"drowned_altar_robbed",value:!0}]},failure:{text:"",effects:[]}}},{text:"Observe from the threshold and leave it intact",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You stand at the water's edge for a long moment. There's nothing to take that wouldn't cost something you can't measure. You leave it and feel the fens press in a little less tightly afterward.",effects:[{type:"morale",value:3}]},failure:{text:"",effects:[]}}}],cooldown:8},{id:"fire_cult_remnants",title:"THE BURNING FAITHFUL",biomes:["cinderwaste"],weight:8,type:"social",illustration:"placeholder",narrative:`Six figures in ashen robes stand in a rough circle on the cracked black plain, arms raised. They are not burning, though the ground around them smokes. When they see you they do not break formation — one simply turns her head and speaks without raising her voice, and somehow you hear her clearly from fifty yards: "Travelers. Will you answer the ember's question?"`,choices:[{text:"Answer their question (Lore TN 10)",visibleCost:null,skillCheck:{skill:"history",stat:"wit",tn:10},outcomes:{success:{text:'You know enough of the old fire theology to answer without offense. The woman who spoke turns back to her circle. "The ember approves," she says. They resume their ritual. When you camp that night, a bundle of supplies has been left at the edge of your fire — dried meat and a sealed flask of clean water.',effects:[{type:"food",value:3},{type:"water",value:2},{type:"flag",key:"fire_cult_approved",value:!0},{type:"morale",value:8},{type:"log",text:"You answered the fire cult's question and they blessed your camp with supplies."}]},failure:{text:'Your answer is wrong or incomplete. The circle does not break but the woman shakes her head. "Walk carefully," she says, and it sounds like a warning. The cinderwaste feels more hostile for the rest of the day.',effects:[{type:"morale",value:-6}]}}},{text:"Refuse and walk past",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You keep your pace. None of them follow. The circle resumes its work as if you were never there. The refusal costs you nothing material and perhaps something harder to name.",effects:[{type:"morale",value:-3}]},failure:{text:"",effects:[]}}},{text:"Attempt to engage them further (Persuasion TN 9)",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:9},outcomes:{success:{text:'The woman speaks at length about what they are guarding: a vent of living fire that predates the empire. They know the cinderwaste like no one alive. She marks your map with safe ground and dangerous pockets. "Tell no one we are here," she asks. You agree.',effects:[{type:"flag",key:"fire_cult_map_marked",value:!0},{type:"morale",value:5},{type:"log",text:"The fire cult marked safe ground on your map through the cinderwaste."}]},failure:{text:"The circle does not want conversation. They go silent and still until you stop trying. You've used up your welcome and their question hangs unanswered.",effects:[{type:"morale",value:-4}]}}}],cooldown:7},{id:"living_ember",title:"THE COAL THAT BREATHES",biomes:["cinderwaste"],weight:7,type:"danger",illustration:"placeholder",narrative:"A coal the size of a man's head pulses at the center of the road — dimming and brightening with a rhythm too regular to be wind or draft. It is warm from six feet away. It is watching you. You are certain it is watching you.",choices:[{text:"Approach and touch it (Arcana TN 11)",visibleCost:null,skillCheck:{skill:"arcana",stat:"wit",tn:11},outcomes:{success:{text:"Your hand closes around it without burning. It pulses once — bright, deep, like a heartbeat — and then goes dark and cold in your palm. A piece of cinderwaste history, extinguished. But in that moment of contact you knew everything it had witnessed for three hundred years. The knowing settles in you like ballast.",effects:[{type:"flag",key:"living_ember_absorbed",value:!0},{type:"morale",value:8},{type:"log",text:"You extinguished a living ember and received its three centuries of memory."}]},failure:{text:"Your hand blisters the moment you touch it. The ember screams — a high, thin sound — and erupts in a gout of cinder-ash that scorches everything within ten feet.",effects:[{type:"damage",targetAll:!0,value:6},{type:"morale",value:-10}]}}},{text:"Extinguish it with water (–1 Water)",visibleCost:"1 water",skillCheck:null,outcomes:{success:{text:"The water hits the ember and it screams — that same thin, awful sound — and goes dark. A small crater remains, smelling of sulfur. You've ended something old. The party doesn't discuss it.",effects:[{type:"water",value:-1},{type:"morale",value:-5}]},failure:{text:"",effects:[]}}},{text:"Walk around it and keep moving",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Wide berth. Fast pace. You feel it tracking you until you're two hundred yards gone. Then nothing.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:9},{id:"ash_oracle",title:"THE VOICE OF CINDERS",biomes:["cinderwaste"],weight:5,type:"discovery",illustration:"placeholder",narrative:'A figure seated in ash up to its waist, motionless, has been here long enough that cinders have drifted up around it like a slow burial. It breathes. You can see that much. It turns its head toward you — eyes white, filmed over, seeing nothing — and speaks in a voice like a furnace drawing air: "You carry something that will change the east. Ask your question or lose the chance forever."',choices:[{text:"Ask about what lies ahead (Lore TN 10)",visibleCost:null,skillCheck:{skill:"history",stat:"wit",tn:10},outcomes:{success:{text:"The oracle speaks in long, slow sentences that take time to parse. What it describes is specific: a crossing that will be guarded, a leader who can be turned, a price that must be paid at the final gate. You write down what you can. It stops speaking mid-sentence and returns to its vigil.",effects:[{type:"flag",key:"oracle_consulted",value:!0},{type:"flag",key:"ash_oracle_prophecy",value:!0},{type:"morale",value:5},{type:"log",text:"The ash oracle spoke of what lies ahead. You recorded its words."}]},failure:{text:"The oracle speaks but the words arrive in the wrong order, or maybe in an order you're not yet wise enough to understand. You leave with fragments that may mean everything or nothing.",effects:[{type:"morale",value:-5},{type:"flag",key:"oracle_consulted",value:!0}]}}},{text:"Ask about the party's fate",visibleCost:null,skillCheck:{skill:"arcana",stat:"wit",tn:9},outcomes:{success:{text:`It speaks three names — not the names of your people, but names they will be called by those who remember them. One name is a word for survivor. One is a word for ghost. One is a word that doesn't translate. "Which is which," it says, "depends entirely on the next three choices you make."`,effects:[{type:"flag",key:"oracle_consulted",value:!0},{type:"flag",key:"oracle_fate_spoken",value:!0},{type:"morale",value:-3},{type:"log",text:"The ash oracle spoke of the party's fate in three untranslatable names."}]},failure:{text:'You ask. It turns toward you and the white eyes go darker. "Not your question to ask," it says. Then silence.',effects:[{type:"flag",key:"oracle_consulted",value:!0},{type:"morale",value:-8}]}}},{text:"Walk past without engaging",visibleCost:null,skillCheck:null,outcomes:{success:{text:`You choose not to know. The oracle's head tracks you as you pass, and when you're beyond earshot someone swears they heard it say "wise." Someone else swears it said "fool."`,effects:[{type:"morale",value:-2}]},failure:{text:"",effects:[]}}}],cooldown:15},{id:"salt_merchant_caravan",title:"THE WHITE TRADERS",biomes:["salt_flats"],weight:8,type:"opportunity",tags:["food_source","water_source"],illustration:"placeholder",narrative:"A disciplined caravan of eight wagons moves in tight formation across the flats, their animals in better condition than anything you've seen in weeks. The lead driver wears a white salt-merchant's sash. They know these flats — they live on them — and they're clearly appraising your party with professional interest.",choices:[{text:"Negotiate for water and provisions (Trade TN 8)",visibleCost:"5 gold",skillCheck:{skill:"trade",stat:"rch",tn:8},outcomes:{success:{text:"The salt-merchant drives a hard bargain but a fair one. Five gold gets you four days of water, two of rations, and a hand-drawn chart of the salt flat's seasonal water holes — worth more than what you paid.",effects:[{type:"gold",value:-5},{type:"water",value:4},{type:"food",value:2},{type:"flag",key:"salt_flat_waterholes",value:!0},{type:"morale",value:6},{type:"log",text:"You traded with salt merchants and acquired a water-hole map of the flats."}]},failure:{text:`She sees through whatever angle you're working and closes the negotiation cleanly. "Come back when you have something worth trading," she says. You part with nothing gained.`,effects:[{type:"morale",value:-3}]}}},{text:"Offer your services as a security escort (Intimidation TN 7)",visibleCost:null,skillCheck:{skill:"intimidation",stat:"grt",tn:7},outcomes:{success:{text:"You present your party as capable escorts and she accepts — one day's travel in formation, keeping pace with the wagons. Slow but provisioned. You arrive at the far edge of the flats fed, watered, and twelve gold heavier.",effects:[{type:"gold",value:12},{type:"food",value:3},{type:"water",value:3},{type:"morale",value:8},{type:"log",text:"You escorted a salt merchant caravan across the flats for good pay."}]},failure:{text:"She has her own guards. Your offer is politely declined and you separate. The caravan shrinks fast in the flat distance.",effects:[]}}},{text:"Ask for news of the road ahead (free)",visibleCost:null,skillCheck:null,outcomes:{success:{text:"The assistant driver is chattier than his employer. He tells you the far edge of the flats has a waystation with a well that's gone brackish but is still usable if you boil it. Better than nothing by a long way.",effects:[{type:"flag",key:"brackish_waystation_known",value:!0},{type:"morale",value:3}]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"mirage_confusion",title:"THE ROAD THAT BENDS",biomes:["salt_flats"],weight:9,type:"danger",illustration:"placeholder",narrative:"The road is clearly visible. Except it bends north, and yesterday it bent south, and the sun has not moved the way it should. You have been walking for three hours and the western peaks look exactly the same distance away as when you started. One party member is quietly insisting you've been walking in a circle.",choices:[{text:"Navigate by sun and stars, trust no landmarks (Navigation TN 10)",visibleCost:null,skillCheck:{skill:"navigation",stat:"hed",tn:10},outcomes:{success:{text:"You cut a straight east-bearing line using sun position alone, ignoring the apparent road, and after forty minutes the mirage breaks. The real road is two hundred yards south of where you thought you were. Close call.",effects:[{type:"morale",value:5},{type:"log",text:"You navigated out of salt flat mirage confusion using celestial bearings."}]},failure:{text:"You lose the afternoon entirely, marching east that turns out to be north, burning water and morale in equal measure. You make camp where you stop because there's no telling where you are.",effects:[{type:"water",value:-3},{type:"food",value:-1},{type:"damage",targetAll:!0,value:3},{type:"morale",value:-12}]}}},{text:"Stop moving and wait for evening (loses day)",visibleCost:null,skillCheck:null,outcomes:{success:{text:"At dusk the mirages collapse and the real geography becomes clear. You've only drifted a mile off course. You camp where you stop, drink carefully, and regain the road at first light.",effects:[{type:"food",value:-1},{type:"water",value:-1},{type:"morale",value:-5}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"night_ambush",title:"THE DARK BETWEEN FIRES",biomes:["all"],weight:8,type:"danger",illustration:"placeholder",narrative:"The second watch ends without incident. The third watch falls asleep. It's the scrape of a boot on stone at the fourth hour of darkness that wakes you — and by then, shadowed figures are already inside the camp perimeter. Bandits. Professionals. They have been watching you for hours.",choices:[{text:"Wake the party and fight (Survival TN 8)",visibleCost:null,skillCheck:{skill:"survival",stat:"hed",tn:8},outcomes:{success:{text:"Your shout and the sound of steel clears sleep from every mind in an instant. You're in defensive position before they close the gap. They weren't expecting organized resistance and the first exchange goes badly for them. They pull back.",effects:[{type:"morale",value:8},{type:"log",text:"You beat off a night ambush before the bandits could press their advantage."}],leadsToCombat:!0},failure:{text:"Your warning comes too late. They're already among you in the dark and you're fighting disoriented, unable to tell friend from shape. Whatever they take, they take cleanly.",effects:[{type:"gold",value:-10},{type:"food",value:-3},{type:"morale",value:-12},{type:"damage",targetAll:!0,value:4}],leadsToCombat:!0}}},{text:"Attempt to bluff them off (Intimidation TN 10)",visibleCost:null,skillCheck:{skill:"intimidation",stat:"grt",tn:10},outcomes:{success:{text:"You rise in the dark and speak at volume — naming their leader by a plausible wrong name, describing the trap you have supposedly already laid, invoking a faction they clearly fear. They believe enough to reconsider. The shapes withdraw.",effects:[{type:"morale",value:6},{type:"log",text:"You bluffed a night bandit gang into withdrawing from camp."}]},failure:{text:"They don't buy it. The bluff makes the lead figure laugh, which makes the others bolder. They close in.",effects:[{type:"damage",targetAll:!0,value:3},{type:"morale",value:-8}],leadsToCombat:!0}}},{text:"Scatter and disappear into the dark (Stealth TN 9)",visibleCost:null,skillCheck:{skill:"stealth",stat:"hed",tn:9},outcomes:{success:{text:"Everyone abandons the camp fast and silent, taking only what they can grab in five seconds. The bandits ransack an empty campsite. You regroup in the dark a quarter mile east and keep moving until dawn.",effects:[{type:"food",value:-2},{type:"morale",value:-4},{type:"log",text:"You scattered into the night, abandoning camp to avoid the bandits."}]},failure:{text:"Someone knocks something over in the dark. The bandits hear the direction of movement and give chase. You fight on ground not of your choosing.",effects:[{type:"damage",targetAll:!0,value:4},{type:"gold",value:-6},{type:"morale",value:-10}],leadsToCombat:!0}}}],cooldown:3},{id:"plague_wagon",title:"THE SEALED CART",biomes:["all"],weight:7,type:"moral",illustration:"placeholder",narrative:'A wagon sits in the middle of the road, sealed shut from the outside with iron brackets, nailed through the doors. The horse is long dead in the traces. From inside: movement. Not much. Weak scratching. Someone is alive in there. Chalked on the side in fading red letters: "PLAGUE — DO NOT OPEN."',choices:[{text:"Open it — no one deserves to die sealed in the dark (Medicine TN 8)",visibleCost:null,skillCheck:{skill:"medicine",stat:"wit",tn:8},outcomes:{success:{text:"An old woman. Sick but not dying — the plague ran its course days ago and she survived. Whoever sealed her in didn't come back to check. You get her water and assess: she's infectious for perhaps another day but already through the worst of it. She tells you the road is clear another three days east. She tells you other things too.",effects:[{type:"water",value:-1},{type:"flag",key:"plague_woman_freed",value:!0},{type:"morale",value:10},{type:"log",text:"You freed a survivor sealed in a plague wagon. She had already recovered."}]},failure:{text:"You open it and find two things: a barely-alive child too sick to have the plague you feared, and a smell that tells you you've already exposed yourselves. You help as best you can and move fast. The fear of infection dogs you for days.",effects:[{type:"water",value:-1},{type:"morale",value:-8},{type:"damage",targetRandom:!0,value:4}]}}},{text:"Leave supplies at the wheel and reseal it",visibleCost:"1 food, 1 water",skillCheck:null,outcomes:{success:{text:"You work through the gaps in the planking: water, a day of food, a note that says help is ahead. The scratching intensifies when they smell the food. You leave quickly, not looking back at the wagon.",effects:[{type:"food",value:-1},{type:"water",value:-1},{type:"morale",value:-6}]},failure:{text:"",effects:[]}}},{text:"Move the wagon off the road and keep going",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You push it into the ditch with your shoulders, clear the road, and leave. The scratching follows you for the next hour.",effects:[{type:"morale",value:-15}]},failure:{text:"",effects:[]}}}],cooldown:8},{id:"sealed_letter",title:"THE MESSENGER",biomes:["all"],weight:9,type:"social",illustration:"placeholder",narrative:`A young man on a lame horse catches up to your party near dusk. He's riding hard even at this pace — urgent. He presents a sealed letter stamped with a mark you half-recognize as official. "You're traveling east?" he asks. "To the March?" His horse cannot go on. "I need this delivered."`,choices:[{text:"Accept the letter and deliver it",visibleCost:null,skillCheck:null,outcomes:{success:{text:`He's grateful to the point of tears. He gives you his remaining provisions and a written introduction to the letter's recipient — a factor in the March who can provide lodging and resupply. "Don't open it," he says. You agree.`,effects:[{type:"food",value:3},{type:"water",value:2},{type:"flag",key:"carrying_sealed_letter",value:!0},{type:"morale",value:5},{type:"log",text:"You accepted a sealed letter for delivery to the East March."}]},failure:{text:"",effects:[]}}},{text:"Accept the letter but read it first (Deception TN 8)",visibleCost:null,skillCheck:{skill:"deception",stat:"wit",tn:8},outcomes:{success:{text:"You break the seal carefully and read: troop movements, a supply route, and a request to hold a specific gate closed for three days. Military intelligence. You reseal it convincingly. You know now what you carry and what it's worth.",effects:[{type:"flag",key:"carrying_sealed_letter",value:!0},{type:"flag",key:"letter_contents_known",value:!0},{type:"morale",value:-3},{type:"log",text:"You read the sealed letter before agreeing to carry it. Military intelligence."}]},failure:{text:"The seal cracks wrong and the resealing is obvious. The messenger hasn't left yet and sees what you've done. The letter is taken back coldly.",effects:[{type:"morale",value:-8}]}}},{text:"Refuse — you carry enough burdens",visibleCost:null,skillCheck:null,outcomes:{success:{text:"He stares at you for a moment, calculating. Then he turns his horse back west. Whatever the letter says, it rides with him.",effects:[{type:"morale",value:-2}]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"child_following",title:"THE SMALL SHADOW",biomes:["all"],weight:6,type:"moral",illustration:"placeholder",narrative:"For the past hour you've noticed a child — perhaps ten years old, dressed in road-worn clothes — following your party at a consistent thirty-yard distance. When you slow, they slow. When you stop, they freeze. They haven't approached. They haven't fled. They are simply following, with the careful patience of someone who has learned that adults either help or don't.",choices:[{text:"Stop and invite them to explain themselves",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:7},outcomes:{success:{text:"A boy. His family's wagon burned two days back, he says — the adults ran different directions and he followed what was moving east because east was away from the fire. He wants nothing except to not be alone. He travels with you to the next settlement, helps with camp chores without being asked, and leaves you with a pressed flower and a map drawing of the road ahead that turns out to be surprisingly accurate.",effects:[{type:"flag",key:"child_traveler_helped",value:!0},{type:"morale",value:10},{type:"food",value:-2},{type:"water",value:-1},{type:"log",text:"A lost child followed your party east. You escorted him to safety."}]},failure:{text:"He won't talk — too scared or too hurt. You give him food and water and point him toward the nearest settlement. He watches you leave without moving.",effects:[{type:"food",value:-1},{type:"water",value:-1},{type:"morale",value:-5}]}}},{text:"Leave extra food on the road and keep walking",visibleCost:"1 food",skillCheck:null,outcomes:{success:{text:"You drop a ration on the road without slowing. A minute later you hear small footsteps stop where you dropped it. The following doesn't resume. Whatever you gave was enough for them to make a different choice.",effects:[{type:"food",value:-1},{type:"morale",value:-3}]},failure:{text:"",effects:[]}}},{text:"Ignore them — they'll turn back eventually",visibleCost:null,skillCheck:null,outcomes:{success:{text:"They follow for another two hours before the road forks and they take the other branch. You never know what became of them. This is the weight the road puts on you.",effects:[{type:"morale",value:-10}]},failure:{text:"",effects:[]}}}],cooldown:7},{id:"war_memorial",title:"THE COUNTING STONE",biomes:["ironmarch"],weight:7,type:"discovery",illustration:"placeholder",narrative:"A stone monolith stands at a crossroads, covered top-to-bottom in carved names. Thousands of them. The names overflow onto surrounding stones and even onto the paving of the road itself. Someone has kept coming back to add more — the newest carvings are recent, the stone still pale and fresh. This war is not over.",choices:[{text:"Read and record what you can (Perception TN 7)",visibleCost:null,skillCheck:{skill:"perception",stat:"hed",tn:7},outcomes:{success:{text:"Among the thousands of names, you find three from a settlement you passed through two weeks back. The war brought here something you thought was just a place. You record what you find. The names make the march harder and more honest.",effects:[{type:"flag",key:"war_memorial_witnessed",value:!0},{type:"morale",value:-5},{type:"log",text:"You read the war memorial and found names you recognized."}]},failure:{text:"Too many names. You scan for something to hold onto and find nothing specific. You stand at the monument long enough that the party grows restless.",effects:[{type:"morale",value:-3}]}}},{text:"Add a name you carry (Lore TN 6)",visibleCost:null,skillCheck:{skill:"history",stat:"wit",tn:6},outcomes:{success:{text:"You carve. The act of adding to the memorial — joining the long count of those who counted — straightens something in the party that had gone crooked. The grief doesn't leave but it finds a right shape.",effects:[{type:"morale",value:10},{type:"flag",key:"added_name_to_memorial",value:!0},{type:"log",text:"You added a name to the war memorial. The party marched lighter afterward."}]},failure:{text:"Your tool slips on the stone. The name comes out wrong. You smooth it over and walk on.",effects:[{type:"morale",value:-2}]}}},{text:"Keep moving — there are too many dead to mourn them all",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You don't stop. You don't look at the names. The stone is behind you in thirty seconds. Something in the party's pace is different — harder, more forward — for the rest of the day.",effects:[{type:"morale",value:-6}]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"deserter_camp",title:"THE GREY COATS",biomes:["ironmarch"],weight:9,type:"social",illustration:"placeholder",narrative:"A dozen men in stripped imperial uniforms have made camp in an old waystation. They've removed their insignia but haven't gotten rid of the soldier in their posture. They watch your party approach with the careful alertness of men who know exactly what their former officers would do to them if found. They're armed. They're hungry. They don't know yet what you are.",choices:[{text:"Approach openly and share a meal (–2 Food)",visibleCost:"2 food",skillCheck:{skill:"persuasion",stat:"rch",tn:8},outcomes:{success:{text:"Shared food unlocks something. Their sergeant — still sergeant by bearing even without the rank — tells you about the road ahead: a garrison checkpoint three leagues on that's recently been reinforced, a bypass through the miller's land to the north, and the location of an unguarded cache left by his regiment before they scattered. He gives you a countersign that might still work at certain posts.",effects:[{type:"food",value:-2},{type:"flag",key:"deserter_countersign",value:!0},{type:"flag",key:"deserter_cache_known",value:!0},{type:"morale",value:6},{type:"log",text:"Deserters shared road intelligence: a cache location and a working countersign."}]},failure:{text:"The mood sours over something — a wrong word, a suspicious look. They ask you to leave. You go, having given food for nothing.",effects:[{type:"food",value:-2},{type:"morale",value:-4}]}}},{text:"Try to recruit one as a guide (–5 Gold)",visibleCost:"5 gold",skillCheck:{skill:"trade",stat:"rch",tn:9},outcomes:{success:{text:"A young one, barely twenty, takes the coin and falls in with your party. He knows the ironmarch intimately — every patrol route, every safe house, every buried cache from three campaigns. He stays with you for two days and then disappears before dawn, leaving behind a detailed sketch of the road ahead.",effects:[{type:"gold",value:-5},{type:"flag",key:"deserter_guide_hired",value:!0},{type:"morale",value:5},{type:"log",text:"A deserter guided you through the ironmarch for two days."}]},failure:{text:"None of them want to leave the group for coin. Too alone, out there. You understand.",effects:[{type:"gold",value:0},{type:"morale",value:-2}]}}},{text:"Give them wide berth",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You circle the waystation and rejoin the road past it. No one follows. Deserters want to be left alone as much as you want to be.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"burning_village_ruins",title:"THE STILL-BURNING TOWN",biomes:["ironmarch"],weight:8,type:"moral",illustration:"placeholder",narrative:"The village ahead is still on fire. Not the old, charred, cold-ash burning you've grown accustomed to — this happened today. Smoke is black and fresh, timbers still collapsing. You can hear screaming that stops and does not resume. Whoever did this is either still here or left minutes ago.",choices:[{text:"Search for survivors (Perception TN 8)",visibleCost:null,skillCheck:{skill:"perception",stat:"hed",tn:8},outcomes:{success:{text:"In a root cellar beneath the mill: four people, one badly burned. You get them out. The burned man doesn't make it through the night, but the other three give you everything they have — a gold coin each, a sealed letter of credit, and the name of who did this. An Iron Legion splinter company, gone east. The same direction you're heading.",effects:[{type:"gold",value:3},{type:"flag",key:"legion_splinter_known",value:!0},{type:"flag",key:"burning_village_helped",value:!0},{type:"morale",value:-5},{type:"log",text:"You pulled survivors from a burning village. They named the Iron Legion splinter responsible."}]},failure:{text:"The smoke is too thick and the structure unsound. You go in twice and pull back both times. No one is in the parts you can reach. Whoever survived got out before you arrived, or didn't survive.",effects:[{type:"damage",targetRandom:!0,value:4},{type:"morale",value:-10}]}}},{text:"Scavenge what the fire hasn't taken (Nature TN 8)",visibleCost:null,skillCheck:{skill:"nature",stat:"hed",tn:8},outcomes:{success:{text:"The smithy's stone floor is intact. The well is intact. You find tools, a coil of rope, and — in the untouched granary annex — three days of grain. You take it in silence. No one feels good about this.",effects:[{type:"food",value:3},{type:"morale",value:-8},{type:"flag",key:"scavenged_burning_village",value:!0},{type:"log",text:"You scavenged supplies from a still-burning village."}]},failure:{text:"The fire has taken everything or the smoke drives you back. The village yields nothing but the smell of it that stays in your clothes.",effects:[{type:"damage",targetRandom:!0,value:2},{type:"morale",value:-8}]}}},{text:"Keep moving — you cannot fight whoever did this",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You put the burning village behind you at a fast walk. You hear it for another hour. The smoke column will be visible from the next settlement — someone will come. Or no one will.",effects:[{type:"morale",value:-15}]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"ash_rain",title:"THE ASH RAIN",biomes:["ashfields","ironmarch","salt_flats"],weight:10,type:"danger",illustration:"placeholder",narrative:"The sky yellows and then the ash comes — not drifting, but falling like real rain, heavy and hot. The smell is wrong: sulphur and something chemical, residue from whatever burns in the eastern mountains. You need to get clear or get covered.",choices:[{text:"Find shelter immediately (Survival TN 8)",visibleCost:null,skillCheck:{skill:"survival",stat:"hed",tn:8},outcomes:{success:{text:"You spot a limestone overhang twenty yards off the road and get everyone under it before the heavy fall hits. You wait it out in cramped discomfort. Everyone's coughing, but no one is damaged.",effects:[{type:"morale",value:-3},{type:"log",text:"You sheltered from an ash rain beneath a limestone overhang."}]},failure:{text:"You can't find shelter fast enough. The party marches through it, covering faces with cloth. By the time it passes they're coated in grey and wheezing.",effects:[{type:"damage",targetAll:!0,value:3},{type:"morale",value:-8},{type:"water",value:-1}]}}},{text:"Push through — cover faces and march",visibleCost:"1 water",skillCheck:{skill:"endurance",stat:"grt",tn:8},outcomes:{success:{text:"You keep the cloth wet and everyone moving. It's brutal and the coughing doesn't stop for hours, but you come out the other side intact and ahead of where you'd be if you'd sheltered.",effects:[{type:"water",value:-1},{type:"morale",value:-4}]},failure:{text:"The ash works into everything — eyes, lungs, wounds. You push through but pay for it.",effects:[{type:"water",value:-1},{type:"damage",targetAll:!0,value:4},{type:"morale",value:-10}]}}}],cooldown:2},{id:"fen_miasma",title:"THE MIASMA",biomes:["fens"],weight:12,type:"danger",illustration:"placeholder",narrative:"A low green haze clings to the water between the hummocks. The smell hits before you can turn back — sweet, rotten, wrong. Something in the air. Your throat tightens.",choices:[{text:"Hold breath and sprint through (Endurance TN 9)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:9},outcomes:{success:{text:"Lungs burning, the party clears the haze in one brutal push. Everyone coughs hard on the far side but the air clears. You're through.",effects:[{type:"morale",value:-4},{type:"log",text:"You sprinted through the fen miasma and cleared it intact."}]},failure:{text:"Not everyone makes it through clean. One member collapses on the far bank, lips dark, breathing wrong. Poisoned.",effects:[{type:"condition",id:"poisoned",name:"Poisoned",duration:4},{type:"morale",value:-10},{type:"log",text:"The fen miasma took one of you — someone is now poisoned."}]}}},{text:"Find another path (–2 hours / food)",visibleCost:"1 food",skillCheck:null,outcomes:{success:{text:"You spend hours picking through the edges of the haze, nose pressed to scarves. The detour costs time and food but everyone arrives intact.",effects:[{type:"food",value:-1},{type:"morale",value:-3}]},failure:{text:"",effects:[]}}}],cooldown:3},{id:"cinderwaste_heat",title:"THE BURNING GROUND",biomes:["cinderwaste"],weight:11,type:"danger",illustration:"placeholder",narrative:"The cinders here are still hot — not glowing, but you feel it through your boots. The air shimmers. By midday it will be unbearable. Already one party member is swaying.",choices:[{text:"Push through now, before peak heat (Endurance TN 8)",visibleCost:"2 water",skillCheck:{skill:"endurance",stat:"grt",tn:8},outcomes:{success:{text:"You force-march through the worst section before the sun peaks. Two water-skins later, you're through. Brutal, but survivable.",effects:[{type:"water",value:-2},{type:"morale",value:-5}]},failure:{text:"The heat breaks one of you. Someone stumbles, goes down, and has to be half-carried the rest of the way. Exhausted — their hands shake, their reactions are slow.",effects:[{type:"water",value:-2},{type:"condition",id:"stunned",name:"Exhausted",duration:2},{type:"morale",value:-10},{type:"log",text:"The cinderwaste heat left one party member exhausted."}]}}},{text:"Rest until dusk and travel at night",visibleCost:"1 food",skillCheck:null,outcomes:{success:{text:"You spend the day in shadow behind a broken wall, sweating through rations. Night travel through the cinderwaste is eerie — orange glow from vents below the rock — but the temperature drops and you make decent time.",effects:[{type:"food",value:-1},{type:"morale",value:2},{type:"log",text:"You crossed the burning ground under stars, orange vents glowing below the cinder."}]},failure:{text:"",effects:[]}}}],cooldown:2},{id:"ironmarch_trap",title:"THE WIRE TRAP",biomes:["ironmarch"],weight:9,type:"danger",illustration:"placeholder",narrative:"Someone has strung iron wire across the road at ankle height — military-gauge, nearly invisible in the grey light. You spot it just as the lead member of your party starts to step.",choices:[{text:"Warn them in time (Perception TN 7)",visibleCost:null,skillCheck:{skill:"perception",stat:"per",tn:7},outcomes:{success:{text:"A shout, a stumble, a saved ankle. You disable the wire carefully and check the next fifty yards for more. Two more strands, same pattern. Someone's been here recently.",effects:[{type:"morale",value:3},{type:"flag",key:"ironmarch_trap_found",value:!0},{type:"log",text:"You found and disarmed wire traps on the Ironmarch road."}]},failure:{text:"The wire catches the lead member's ankle and bites deep. A bad cut, badly placed — they'll be bleeding the rest of the march.",effects:[{type:"condition",id:"bleeding",name:"Bleeding",duration:3},{type:"damage",targetRandom:!0,value:4},{type:"morale",value:-7},{type:"log",text:"A hidden wire trap caught one of your party — someone is bleeding."}]}}},{text:"Turn back and find another route",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Caution costs an hour but saves an ankle. You circle wide through the marsh grass and rejoin the road half a league past the trap.",effects:[{type:"food",value:-1},{type:"morale",value:-2}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"hollow_rot_water",title:"THE TAINTED POOL",biomes:["hollows"],weight:10,type:"survival",tags:["water_source"],illustration:"placeholder",narrative:"The pool looks clean. Clear, even, with a faint blue cast that water doesn't usually have. You're desperately short on water and the next marked source is two days out. Something about it makes the hairs rise — but the party is thirsty.",choices:[{text:"Drink — you have no choice (Medicine TN 9)",visibleCost:null,skillCheck:{skill:"medicine",stat:"wit",tn:9},outcomes:{success:{text:"You boil what you can and ration it carefully. Someone has a bad night but it passes. The blue cast was mineral, not rot. You're lucky.",effects:[{type:"water",value:3},{type:"morale",value:-4}]},failure:{text:"The water was wrong. By nightfall one party member is running a fever, cramping, unable to keep anything down. Poisoned.",effects:[{type:"water",value:2},{type:"condition",id:"poisoned",name:"Poisoned",duration:5},{type:"morale",value:-12},{type:"log",text:"Someone drank tainted water from a Hollows pool."}]}}},{text:"Leave it and ration strictly",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You walk away from the pool with dry throats and spend the next day managing thirst carefully. Hard, but clean.",effects:[{type:"water",value:-1},{type:"morale",value:-5}]},failure:{text:"",effects:[]}}}],cooldown:3},{id:"greywood_thornwall",title:"THE THORNWALL",biomes:["greywood"],weight:8,type:"danger",illustration:"placeholder",narrative:"The old growth has closed across the path. Not naturally — the thorns are woven, interlocked, as if someone trained them into a barrier years ago. The gaps are just wide enough to squeeze through, but the thorns are long and barbed.",choices:[{text:"Force through carefully (Agility TN 7)",visibleCost:null,skillCheck:{skill:"athletics",stat:"agi",tn:7},outcomes:{success:{text:"You move slowly, one at a time, finding the angles. Twenty minutes to get everyone through. Scratched, clothing torn, but nothing serious.",effects:[{type:"morale",value:-2}]},failure:{text:"The thorns catch more than cloth. One party member panics when a barb hooks deep and tears free wrong — the wound opens badly.",effects:[{type:"condition",id:"bleeding",name:"Bleeding",duration:3},{type:"damage",targetRandom:!0,value:5},{type:"morale",value:-8}]}}},{text:"Hack a path through (costs time)",visibleCost:"1 food",skillCheck:null,outcomes:{success:{text:"An hour's work with whatever blades you carry. The path isn't elegant but it's clear, and you won't leave tracks for anyone following.",effects:[{type:"food",value:-1},{type:"morale",value:-2}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"mountain_cold_snap",title:"THE COLD SNAP",biomes:["mountains"],weight:11,type:"danger",illustration:"placeholder",narrative:"The temperature drops thirty degrees in an hour. No warning — just the wind turning and the sky going white. You're exposed on a ridge with no shelter visible. The cold is the kind that makes fingers slow and thinking slower.",choices:[{text:"Make for the rock faces and dig in (Survival TN 9)",visibleCost:null,skillCheck:{skill:"survival",stat:"hed",tn:9},outcomes:{success:{text:"You find a wind-break in the lee of a boulder field and pile in together. It's miserable but survivable. When the temperature steadies three hours later you push on.",effects:[{type:"morale",value:-5},{type:"log",text:"You waited out a mountain cold snap in a boulder wind-break."}]},failure:{text:"No good shelter, no good options. You keep moving but the cold reaches bone. Someone's fingers go white, their reactions dulled — they won't be fighting their best.",effects:[{type:"condition",id:"stunned",name:"Frostbitten",duration:3},{type:"damage",targetAll:!0,value:3},{type:"morale",value:-12},{type:"log",text:"A mountain cold snap left one of your party frostbitten."}]}}},{text:"Burn extra fuel and push hard",visibleCost:"2 fuel",skillCheck:null,outcomes:{success:{text:"You torch the emergency fuel and keep moving. The warmth is chemical but real. You outrun the worst of the snap and descend into a sheltered valley by nightfall.",effects:[{type:"fuel",value:-2},{type:"morale",value:-3}]},failure:{text:"",effects:[]}}}],cooldown:2},{id:"salt_flats_sun",title:"THE BLEACHING SUN",biomes:["salt_flats"],weight:9,type:"survival",illustration:"placeholder",narrative:"Eight hours of open flats with no shadow. The sun reflects off the salt so you're getting it from above and below. By midday the party is barely speaking. By afternoon one member is moving wrong — slow, confused, stumbling.",choices:[{text:"Push through to the far dunes (Endurance TN 10)",visibleCost:"3 water",skillCheck:{skill:"endurance",stat:"grt",tn:10},outcomes:{success:{text:"Brutal and wordless. You reach the dunes at dusk, everyone upright. Half your water is gone but the salt is behind you.",effects:[{type:"water",value:-3},{type:"morale",value:-6}]},failure:{text:"The sun takes the weakest one first. Heat-addled, stumbling, unable to track where they are. They'll need rest before they're sharp again.",effects:[{type:"water",value:-3},{type:"condition",id:"stunned",name:"Heat-Addled",duration:2},{type:"morale",value:-14},{type:"log",text:"The salt flats sun left one party member heat-addled."}]}}},{text:"Camp until dusk and night-march",visibleCost:"1 food, 1 water",skillCheck:null,outcomes:{success:{text:"You make a miserable camp in the open salt, sleeping in scraps of shade. Night comes and the temperature drops fast. You cross under the stars in three hours, the crust glowing pale beneath your boots.",effects:[{type:"food",value:-1},{type:"water",value:-1},{type:"morale",value:4},{type:"log",text:"You crossed the salt flats at night. The crust glowed pale beneath your boots."}]},failure:{text:"",effects:[]}}}],cooldown:3},{id:"ashfields_corpse_gas",title:"THE DEAD HOLLOW",biomes:["ashfields","hollows"],weight:8,type:"danger",illustration:"placeholder",narrative:"The dip in the road fills with a grey-white gas that sits perfectly still in the windless air. Old battlefield, maybe. Or something that died large down there and has been rotting long enough to produce this. You can't see the far side.",choices:[{text:"Cross fast — hold breath (Endurance TN 8)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:8},outcomes:{success:{text:"Lungs at capacity, moving hard. The gas is thick but low — you stay high and sprint. Twenty seconds and you're out, gasping clean air on the far side.",effects:[{type:"morale",value:-3}]},failure:{text:"Someone doesn't make it clean. They inhale before they're through and go down on the far side, retching. Poisoned — their colour is wrong.",effects:[{type:"condition",id:"poisoned",name:"Poisoned",duration:4},{type:"morale",value:-10},{type:"log",text:"Someone inhaled dead hollow gas and is now poisoned."}]}}},{text:"Go around the hollow (1 hour)",visibleCost:null,skillCheck:null,outcomes:{success:{text:"The long way around. Dry grass, no trail, stumbling over hidden rocks. An hour lost. But everyone arrives intact.",effects:[{type:"morale",value:-2}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"pale_commissar_first",title:"THE PALE COMMISSAR",biomes:["ashfields","ironmarch","salt_flats","greywood","steppe","east_march","mountains","fens","cinderwaste","hollow_reaches","storm_coast","amber_forest","thorn_mere","hollows"],minDay:3,maxDay:3,weight:0,mustTriggerOnDay:3,oneShot:!0,type:"danger",illustration:"placeholder",narrative:`A rider in grey wool stops ahead of you, one hand resting on a ledger the size of a gravestone. He is thin as a winter branch, his face pitted by old pox, and he wears the silver chain of an Imperial Census Commissar. He studies you with the patience of a man who has never been refused.

"Papers," he says. Not a question. "All travel requires Imperial registration. Those who cannot produce documentation are recorded as unregistered migrants — subject to levy, conscription, or detainment at my discretion." He opens his ledger.`,choices:[{text:"Produce forged papers or talk your way through (Persuasion TN 11)",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:11},outcomes:{success:{text:`He scrutinises the papers — or your story — for a long, cold moment. Something in his expression doesn't shift but his pen moves, and he records something in the ledger. "Registered. Move on." He watches you go. The back of your neck stays cold for the next mile.`,effects:[{type:"flag",key:"commissar_met",value:!0},{type:"flag",key:"commissar_fooled",value:!0},{type:"morale",value:-5},{type:"log",text:"You talked past the Pale Commissar. He registered you — under what name, you're not sure."}]},failure:{text:'His pen stops. He reads it again. Then he looks at you over the ledger with the expression of a man who has caught hundreds of liars and finds it neither satisfying nor interesting. "Unregistered. Warrant to follow." He writes something in red. His hand moves to a whistle at his throat.',effects:[{type:"flag",key:"commissar_met",value:!0},{type:"flag",key:"commissar_defied",value:!0},{type:"morale",value:-10},{type:"log",text:"The Pale Commissar saw through your story. He's filed a warrant."}],leadsToCombat:!0}}},{text:"Bribe him — press gold into his hand (–15 Gold)",visibleCost:"15 gold",skillCheck:null,outcomes:{success:{text:'The coins disappear into his sleeve without him looking at them. His pen scratches something in the ledger. "Registered under auxiliary exemption." He closes the book. "The next commissar may not be so flexible." He rides east. You watch him go.',effects:[{type:"gold",value:-15},{type:"flag",key:"commissar_met",value:!0},{type:"flag",key:"commissar_bribed",value:!0},{type:"morale",value:-3},{type:"log",text:"You bribed the Pale Commissar. He rode on — for now."}]},failure:{text:"",effects:[]}}},{text:"Refuse — you answer to no empire",visibleCost:null,skillCheck:null,outcomes:{success:{text:'"Then you are unregistered." He writes it down with the same disinterest he might record a weather observation. Then he puts two fingers to his lips and a sharp whistle cuts the still air. From the treeline behind him, three soldiers emerge with crossbows raised. "Comply or be catalogued as hostile." His voice is bored. His soldiers are not.',effects:[{type:"flag",key:"commissar_met",value:!0},{type:"flag",key:"commissar_defied",value:!0},{type:"morale",value:-8},{type:"log",text:"You refused the Pale Commissar. His soldiers have you surrounded."}],leadsToCombat:!0},failure:{text:"",effects:[]}}},{text:"Attack first — don't give him the chance (Combat)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:9},outcomes:{success:{text:"You move before the whistle can sound. The commissar scrambles back with a speed that surprises you — he's survived worse than you. His soldiers scatter into the brush as you press the attack. He retreats, ledger clutched to his chest, shouting something about warrants and records. He's alive. So are you. For now.",effects:[{type:"flag",key:"commissar_met",value:!0},{type:"flag",key:"commissar_defied",value:!0},{type:"damage",targetRandom:!0,value:3},{type:"morale",value:5},{type:"log",text:"You drove off the Pale Commissar before he could call his soldiers. He fled with his ledger."}],leadsToCombat:!0},failure:{text:"The soldiers were closer than you thought. They had the angles. You take a bolt before the commissar even reaches for his whistle. He watches the skirmish from horseback, writing notes. You break and run.",effects:[{type:"flag",key:"commissar_met",value:!0},{type:"flag",key:"commissar_defied",value:!0},{type:"damage",targetRandom:!0,value:7},{type:"morale",value:-15},{type:"log",text:"The Pale Commissar's soldiers were ready. You took a bolt and ran."}]}}}],cooldown:999},{id:"commissar_warrant",title:"THE WARRANT",biomes:["ashfields","ironmarch","salt_flats","greywood","steppe","east_march","mountains","fens","cinderwaste","hollow_reaches","storm_coast","amber_forest","thorn_mere","hollows"],minDay:8,maxDay:14,weight:0,requireFlag:"commissar_defied",requireNotFlag:"commissar_warrant_seen",oneShot:!0,type:"danger",illustration:"placeholder",narrative:`Nailed to a dead tree at a crossroads: a folded Imperial warrant, still damp. You recognise the seal — silver chain and quill. The Pale Commissar's mark.

You pull it down. A rough sketch of your party. The number is wrong by one, which means he counted you from a distance before he ever rode out. At the bottom: "UNREGISTERED HOSTILES. Reward: 25 gold per detainee. Commissar Vael Drast, Third Census Bureau." 

Somewhere behind you, he is still watching the roads.`,choices:[{text:"Take the warrant down and destroy it",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You tear it into small pieces and scatter them in the ash. It won't stop the next posting — his bureau makes copies. But it feels like something.",effects:[{type:"flag",key:"commissar_warrant_seen",value:!0},{type:"morale",value:-8},{type:"log",text:"You found and destroyed Commissar Drast's warrant. More are out there."}]},failure:{text:"",effects:[]}}},{text:"Study it carefully — learn what he knows (Perception TN 9)",visibleCost:null,skillCheck:{skill:"perception",stat:"hed",tn:9},outcomes:{success:{text:"The sketch is too accurate for a brief roadside encounter. He had someone watching you before the meeting. The count is off by one — he missed whoever was covering the rear. That's useful. He doesn't know your full strength. You take the warrant and keep it.",effects:[{type:"flag",key:"commissar_warrant_seen",value:!0},{type:"flag",key:"commissar_intel",value:!0},{type:"morale",value:-5},{type:"log",text:"You studied the warrant. Commissar Drast undercounted your party — he has a blindspot."}]},failure:{text:"It's what you expected: a warrant, a reward, your descriptions. You tear it down and move on, one eye behind you.",effects:[{type:"flag",key:"commissar_warrant_seen",value:!0},{type:"morale",value:-8},{type:"log",text:"Commissar Drast has posted warrants. You tore one down."}]}}},{text:"Leave it — let him think you haven't seen it",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Smart. Anyone who reports back to him will say the warrant was untouched. Let him think you're unaware you're being hunted. You memorise the details and walk on.",effects:[{type:"flag",key:"commissar_warrant_seen",value:!0},{type:"flag",key:"commissar_left_warrant",value:!0},{type:"morale",value:-6},{type:"log",text:"You left Drast's warrant intact. Let him think you didn't see it."}]},failure:{text:"",effects:[]}}}],cooldown:999},{id:"commissar_second_meeting",title:"COMMISSAR DRAST AGAIN",biomes:["ashfields","ironmarch","salt_flats","greywood","steppe","east_march","mountains","fens","cinderwaste","hollow_reaches","storm_coast","amber_forest","thorn_mere","hollows"],minDay:15,maxDay:22,weight:0,requireFlag:"commissar_met",requireNotFlag:"commissar_final_met",oneShot:!0,type:"danger",illustration:"placeholder",narrative:`The grey horse is hitched to a milestone at a fork in the road. Commissar Drast stands beside it, ledger closed under one arm. No soldiers visible — but you've learned not to trust that.

He doesn't reach for his whistle this time. He watches you approach with the expression of a man completing an errand.

"I find you again," he says. "The empire's roads are long. So is my memory." A pause. "I have a proposal."`,choices:[{text:"Hear him out",visibleCost:null,skillCheck:null,outcomes:{success:{text:`"There is a settlement ahead — Harrow's Gate. A man named Brek Mollen has been evading registration for eleven years. He moves with a refugee column. Find him and bring me his mark — a branded left thumb, or the thumb itself, I'm not particular — and I will expunge your warrants. All of them." He holds out a folded paper with Mollen's description.

He is asking you to hunt a refugee for him.`,effects:[{type:"flag",key:"commissar_task_offered",value:!0},{type:"morale",value:-5},{type:"log",text:"Commissar Drast offered a deal: find refugee Brek Mollen in exchange for clearing your warrants."}]},failure:{text:"",effects:[]}}},{text:"Attack him — end this now (Combat TN 12)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:12},outcomes:{success:{text:"He's faster than he looks — a short blade from inside his coat — but not fast enough. You disarm him and leave him face-down in the road dust, breathing. He'll live. He'll also file reports, send riders, put every garrison between here and the border on alert. But he'll do that anyway. At least this time he bleeds for it. You take his ledger.",effects:[{type:"flag",key:"commissar_beaten",value:!0},{type:"flag",key:"commissar_final_met",value:!0},{type:"item",itemId:"commissar_ledger"},{type:"damage",targetRandom:!0,value:5},{type:"morale",value:10},{type:"log",text:"You put Commissar Drast in the road and took his ledger. The warrants are worse now, but so is he."}],leadsToCombat:!0},failure:{text:'His soldiers were in the brush after all — four of them, close. You were good enough to hurt him before they arrived but not good enough to stop them. He watches you run from the road, holding a cloth to his face. "Record them as armed and violent," you hear him say.',effects:[{type:"flag",key:"commissar_defied",value:!0},{type:"damage",targetRandom:!0,value:8},{type:"damage",targetRandom:!0,value:4},{type:"morale",value:-18},{type:"log",text:"You tried to take down Commissar Drast but his soldiers intervened. You fled hurt."}]}}},{text:"Refuse the deal — he can keep his warrants",visibleCost:null,skillCheck:null,outcomes:{success:{text:'"I assumed as much." He opens his ledger and makes a note. "Then you remain outstanding warrants. Have a safe journey." He turns back to his horse. As if this is paperwork, not a death sentence. As if you are already accounted for in some column headed: "Eventual."',effects:[{type:"flag",key:"commissar_task_refused",value:!0},{type:"flag",key:"commissar_final_met",value:!0},{type:"morale",value:-10},{type:"log",text:"You refused Commissar Drast's deal. He updated his ledger and let you walk."}]},failure:{text:"",effects:[]}}},{text:"Agree to hunt Mollen",visibleCost:null,skillCheck:null,outcomes:{success:{text:'He hands you the paper. "Eleven days. After that, the warrants become priority classification." He mounts his horse and rides north without looking back. The description in your hand is of a man who, by all accounts, fled a labour camp with his family. The warrant price on him is forty gold. You have eleven days to decide what kind of people you are.',effects:[{type:"flag",key:"commissar_task_accepted",value:!0},{type:"flag",key:"commissar_final_met",value:!0},{type:"morale",value:-12},{type:"log",text:"You agreed to find refugee Brek Mollen for Commissar Drast. Eleven days."}]},failure:{text:"",effects:[]}}}],cooldown:999},{id:"boss_pale_warden",isBoss:!0,minEscalation:60,weight:3,cooldown:99,biomes:["ironmarch","east_march"],type:"danger",title:"THE PALE WARDEN",illustration:"placeholder",narrative:"The road narrows between two dead elms and something stands in the gap — seven feet of blackened plate, motionless as a tombstone. No crest, no pennant. The armour is old enough that the joints have fused with rust or something darker. It has been waiting. One gauntleted hand opens, palm up. The other rests on a sword that is too large to be practical and too clean to be old.",choices:[{text:"Pay the toll in blood — stand and fight (Combat TN 13)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:13},outcomes:{success:{text:"The Warden absorbs three blows that would have killed an ordinary soldier before something in it finally gives — a seam of rust splitting open along the gorget, black fluid weeping out. It steps aside. On the ground where it stood: a purse heavy with iron coin and a vial of something clear.",effects:[{type:"gold",value:40},{type:"medicine",value:2},{type:"morale",value:12},{type:"flag",key:"defeated_pale_warden",value:!0},{type:"log",text:"You bested the Pale Warden and claimed its toll-purse."}]},failure:{text:"The Warden moves with horrible efficiency. One strike opens a party member from shoulder to hip. Another folds a second fighter against the elm with a sound like green wood cracking. You are on the ground before you understand you lost.",effects:[{type:"damage",targetRandom:!0,value:9},{type:"damage",targetRandom:!0,value:7},{type:"condition",id:"bleeding",name:"Bleeding",duration:3},{type:"morale",value:-25},{type:"log",text:"The Pale Warden cut the party down. You fled broken and bleeding."}]}}},{text:"Pay in gold — meet its demand (–30 Gold)",visibleCost:"30 gold",skillCheck:{skill:"persuasion",stat:"rch",tn:10},outcomes:{success:{text:"The coins disappear into the gauntlet one by one. The Warden counts them without looking down — it is watching your faces the whole time. When the last coin vanishes it steps off the road with a sound like a slow avalanche. The road is open. Your purse is much lighter.",effects:[{type:"gold",value:-30},{type:"morale",value:-8},{type:"flag",key:"paid_pale_warden",value:!0},{type:"log",text:"You paid the Pale Warden's toll and passed unmolested."}]},failure:{text:"You try to negotiate — fewer coins, a different arrangement. The Warden tilts its helm half an inch, a motion of contempt so precise it must have been practiced. Then it draws the sword. You scatter into the scrub and lose a day circling back.",effects:[{type:"gold",value:-15},{type:"morale",value:-20},{type:"log",text:"The Pale Warden rejected your bargain. You fled into the scrub."}]}}},{text:"Leave the road — find a way around",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You watch it for a long time from the tree line. It doesn't move. It doesn't patrol. It only holds the road. By nightfall you have found a dry creek bed that cuts well wide of the elms. The crossing costs half the day and the soles of two boots, but you are through.",effects:[{type:"morale",value:-20},{type:"food",value:-1},{type:"log",text:"You abandoned the road and crept wide of the Pale Warden."}]},failure:{text:"",effects:[]}}}]},{id:"boss_ashen_colossus",isBoss:!0,minEscalation:60,weight:3,cooldown:99,biomes:["ashfields","salt_flats","cinderwaste"],type:"danger",title:"THE ASHEN COLOSSUS",illustration:"placeholder",narrative:"You hear it before you see it — a low grinding like millstones, the crack of something enormous settling its weight. Then the silhouette rises out of the haze: thirty feet of fused bone and slag, skulls the size of boulders pressed into a torso like river stones in mortar. It has no eyes. It has no mouth. It moves toward your position with the slow certainty of a tide, and the ground shudders with each step.",choices:[{text:"Bring it down — aim for the joints (Endurance TN 14)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:14},outcomes:{success:{text:"The joints are the answer — you can see the seams where living ash has calcified into mortar. Hammer those points long enough and the mass becomes unsupported. One knee fails, then the other. It collapses forward like a falling tower and the impact sends a shockwave of hot grit across the flats. In the rubble: a hollow chest cavity packed with the belongings of every creature it has absorbed.",effects:[{type:"gold",value:35},{type:"medicine",value:3},{type:"food",value:2},{type:"morale",value:18},{type:"flag",key:"defeated_ashen_colossus",value:!0},{type:"log",text:"You brought down the Ashen Colossus and raided its hollow chest."}]},failure:{text:"One sweep of its arm clears the party like rag dolls. You wake face-down in the salt with your ears ringing and two members badly crushed. It has moved on — it does not stop to finish things.",effects:[{type:"damage",targetRandom:!0,value:10},{type:"damage",targetRandom:!0,value:8},{type:"condition",id:"exhausted",name:"Crushed",duration:4},{type:"morale",value:-28},{type:"log",text:"The Ashen Colossus swept the party aside. You came to in the ash with broken ribs."}]}}},{text:"Read its movement — find the blind spot (Survival TN 12)",visibleCost:null,skillCheck:{skill:"survival",stat:"wit",tn:12},outcomes:{success:{text:"It navigates by vibration — footfalls, breathing, the rattle of your equipment. You work it out over tense minutes watching it track the wrong direction. Spread out, move slow, step on the hard crust where you leave no print. It passes within forty feet and never adjusts course. Everyone is shaking when it disappears into the haze.",effects:[{type:"morale",value:8},{type:"flag",key:"evaded_ashen_colossus",value:!0},{type:"log",text:"You read the Colossus and slipped past it unseen."}]},failure:{text:"You misread the timing. A heavy-footed scramble triggers it mid-pass — it pivots faster than anything that size has a right to and a fist the size of a cart comes down. One party member takes the edge of the blow and folds. The rest of you run, abandoning half your supplies where they fell.",effects:[{type:"damage",targetRandom:!0,value:8},{type:"food",value:-3},{type:"water",value:-2},{type:"morale",value:-22},{type:"log",text:"The Colossus caught you mid-evasion. You ran and left supplies behind."}]}}},{text:"Run — get clear before it closes",visibleCost:null,skillCheck:null,outcomes:{success:{text:"No shame in it. You run until your lungs give out and the grinding fades behind you. An hour later you find the road again, somewhere further east than you planned. The Colossus is still out there on the flats, following something else now.",effects:[{type:"morale",value:-20},{type:"water",value:-1},{type:"log",text:"You fled the Ashen Colossus and lost your bearings on the flats."}]},failure:{text:"",effects:[]}}}]},{id:"boss_choir_of_rot",isBoss:!0,minEscalation:60,weight:3,cooldown:99,biomes:["greywood","fens","hollows"],type:"danger",title:"THE CHOIR OF ROT",illustration:"placeholder",narrative:"The sound reaches you first — a low unified moan, not of pain but of something stranger, like a congregation locked in a single long note. Then the treeline parts and you see them: scores of plague-hollowed moving in lockstep, shoulder to shoulder, filling the road and the ditch and the dead brush on both sides. Their mouths are open. Their eyes are clouded white. They are not running. They are simply walking forward in a wall of rotting flesh that stretches as far as you can see.",choices:[{text:"Break through the flank — find the weak point (Endurance TN 13)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:13},outcomes:{success:{text:"The outer edge of the formation is thinner — the Choir curves inward toward its own centre, drawn by some shared gravity. You hit the flank hard and fast, cutting a channel through bodies that barely register you. Something wet, something foul, but you are through in under a minute and the wall closes behind you like water. You emerge gasping on the far side, alive.",effects:[{type:"medicine",value:-1},{type:"morale",value:10},{type:"flag",key:"breached_choir_of_rot",value:!0},{type:"log",text:"You cut through the Choir of Rot's flank and came out the other side."}]},failure:{text:"The wall swallows you. Hands — dozens of them — and the noise up close is deafening, the moan vibrating in your teeth. You fight free but not clean. Two party members are bitten. The rot is already under their skin, working inward.",effects:[{type:"damage",targetRandom:!0,value:7},{type:"damage",targetRandom:!0,value:6},{type:"condition",id:"poisoned",name:"Plague-Touched",duration:5},{type:"morale",value:-30},{type:"log",text:"The Choir of Rot dragged you under. You escaped with plague-bite."}]}}},{text:"Burn a path — use your fuel (–3 Fuel)",visibleCost:"3 fuel",skillCheck:{skill:"survival",stat:"wit",tn:10},outcomes:{success:{text:"Fire is the one thing they react to. The wall recoils from the flame, the Choir's moan shifting register into something closer to alarm. You torch the ditch on both sides and walk through the gap while it holds. The smoke is thick with a sweetness you try not to name. By the time the fire burns down you are well clear.",effects:[{type:"fuel",value:-3},{type:"morale",value:-5},{type:"flag",key:"burned_choir_of_rot",value:!0},{type:"log",text:"You burned a gap through the Choir of Rot and walked through the smoke."}]},failure:{text:"The fire spreads wrong — a wet wind off the fens drives it back toward you. You scatter and reconverge a quarter mile back the way you came, coughing, with three members singed and a full fuel supply burned for nothing.",effects:[{type:"fuel",value:-3},{type:"damage",targetRandom:!0,value:6},{type:"condition",id:"exhausted",name:"Smoke-Sick",duration:2},{type:"morale",value:-20},{type:"log",text:"Your fire failed. The Choir pushed you back singed and emptyhanded."}]}}},{text:"Retreat into the fens — wait them out",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You pull back into the standing water and the dead reeds and watch the Choir pass from thirty feet away, half-submerged in black fen water. They do not leave the road. Whatever compels them keeps them on the hard ground. Two hours later the last of them shuffles past and the road is empty. You are soaked through and demoralized but intact.",effects:[{type:"morale",value:-20},{type:"condition",id:"exhausted",name:"Fen-Soaked",duration:1},{type:"log",text:"You hid in the fens and waited for the Choir of Rot to pass."}]},failure:{text:"",effects:[]}}}]},{id:"boss_ironwatch_checkpoint",isBoss:!0,minEscalation:60,weight:3,cooldown:99,biomes:["ironmarch","mountains","east_march"],type:"danger",title:"THE IRONWATCH CHECKPOINT",illustration:"placeholder",narrative:"The checkpoint wasn't here yesterday — you would have heard. Someone built it fast: sharpened stakes, an oil lantern, three soldiers in fresh-polished heavy iron who are watching the road with the particular attention of men given a description. One of them is holding a broadsheet. As you come close enough to read it you realise with cold certainty that the illustration on the broadsheet is one of your party.",choices:[{text:"Bluff through — deny everything (Persuasion TN 13)",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:13},outcomes:{success:{text:"Steady hands and a steady voice. Wrong road, wrong people, wrong day — you feed them a story built from half-truths and they want to believe it because the alternative means paperwork. The sergeant folds the broadsheet away. You walk through slowly, not looking back until the checkpoint is a quarter mile behind you and you allow yourself to breathe again.",effects:[{type:"morale",value:10},{type:"flag",key:"bluffed_ironwatch",value:!0},{type:"log",text:"You talked the Ironwatch checkpoint into letting you through."}]},failure:{text:"The sergeant's eyes go from the broadsheet to your face and back once, very slowly. Then he calls for irons. You run. They are faster than they look and better coordinated. By the time you shake them in the rocks you have injuries that will not be ignored and no idea how far the pursuit extends.",effects:[{type:"damage",targetRandom:!0,value:8},{type:"damage",targetRandom:!0,value:6},{type:"condition",id:"bleeding",name:"Blade-Cut",duration:3},{type:"morale",value:-25},{type:"flag",key:"burned_by_ironwatch",value:!0},{type:"log",text:"The Ironwatch saw through you. You ran and took steel for it."}]}}},{text:"Bribe the sergeant — make it worth his silence (–25 Gold)",visibleCost:"25 gold",skillCheck:{skill:"persuasion",stat:"wit",tn:11},outcomes:{success:{text:"The sergeant's expression doesn't change. He takes the coin without looking at it and pockets it with the broadsheet simultaneously. He waves his soldiers back to their fire and tells you the east fork is unguarded at this hour, speaking to the middle distance, not to you. It is a practised transaction. You are not his first.",effects:[{type:"gold",value:-25},{type:"morale",value:5},{type:"flag",key:"bribed_ironwatch",value:!0},{type:"log",text:"You bribed the Ironwatch sergeant and walked free."}]},failure:{text:"He takes the gold and calls for his men anyway. Either you misread him entirely or this particular checkpoint has been briefed against exactly this move. You scatter into the dark with lighter pockets and enemies closing from two sides.",effects:[{type:"gold",value:-25},{type:"damage",targetRandom:!0,value:7},{type:"condition",id:"exhausted",name:"Hunted",duration:2},{type:"morale",value:-22},{type:"log",text:"The sergeant took your gold and raised the alarm anyway."}]}}},{text:"Slip off the road before they see you clearly",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You are just far enough out that a casual look won't resolve the faces. You peel off into the scree and work around the checkpoint's eastern blind side over the next two hours, moving slow and low. By the time you regain the road the checkpoint is a distant light behind you. They never called out. They may not have seen you. Or they may have, and decided you weren't worth the cold.",effects:[{type:"morale",value:-20},{type:"food",value:-1},{type:"log",text:"You crept around the Ironwatch checkpoint through the dark."}]},failure:{text:"",effects:[]}}}]},{id:"wayfarer_safe_house",weight:6,cooldown:6,biomes:["greywood","fens","amber_forest","steppe"],type:"opportunity",tags:["food_source","water_source"],title:"Wayfarer Safe House",illustration:"placeholder",narrative:"A lantern burns in a farmhouse window in the pattern of the Wayfarers' Compact — three short flashes, one long. If you know it, you know you can knock.",choices:[{text:"Knock on the door (requires Wayfarers' Compact standing)",visibleCost:null,requireFactionRep:{factionId:"wayfarers_compact",min:10},skillCheck:null,outcomes:{success:{text:"A tired man opens the door, sees your faces, and steps back. Food, water, a dry floor. Before dawn he gives you a sealed message for a contact two days east — the Compact won't forget.",effects:[{type:"food",value:4},{type:"water",value:4},{type:"morale",value:10},{type:"factionRep",factionId:"wayfarers_compact",value:5},{type:"log",text:"The Wayfarers' safe house took you in for the night."}]},failure:{text:"",effects:[]}}},{text:"Pass by without knocking",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You walk on. The lantern blinks behind you. You may never know what you passed up.",effects:[{type:"morale",value:-2}]},failure:{text:"",effects:[]}}}]},{id:"salt_guild_caravan",weight:7,cooldown:5,biomes:["salt_flats","steppe","east_march"],type:"opportunity",tags:["food_source","water_source"],title:"Salt Guild Caravan",illustration:"placeholder",narrative:"A Salt Traders' Guild caravan is camped in the lee of a dune wall. Their factor watches you approach with professional wariness — not hostility, but careful accounting.",choices:[{text:"Trade (Guild standing improves your prices)",visibleCost:null,skillCheck:{skill:"trade",stat:"wit",tn:9},factionBonus:{factionId:"salt_traders_guild",perTier:1},outcomes:{success:{text:"The factor offers fair rates — provisions, medicine, water. High guild standing gets a pouch of coin as a courtesy. The road has fewer thorns when the guild knows your name.",effects:[{type:"food",value:3},{type:"water",value:3},{type:"medicine",value:1},{type:"factionRep",factionId:"salt_traders_guild",value:3},{type:"log",text:"You traded with a Salt Guild caravan."}]},failure:{text:"The factor won't budge on pricing. You buy one day's water and move on.",effects:[{type:"water",value:2},{type:"gold",value:-5},{type:"morale",value:-3}]}}},{text:"Ask for work — escort or delivery",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:10},outcomes:{success:{text:"They need a package delivered to a waystation two days east. The guild remembers.",effects:[{type:"gold",value:10},{type:"factionRep",factionId:"salt_traders_guild",value:8},{type:"flag",key:"guild_delivery_active",value:!0},{type:"log",text:"You took a Salt Guild delivery contract."}]},failure:{text:"The factor decides you're not reliable enough for contracted work. Not an insult — just business.",effects:[{type:"morale",value:-2}]}}}]},{id:"ironwatch_informant",weight:5,cooldown:8,biomes:["ironmarch","east_march","mountains"],type:"social",title:"Ironwatch Informant",illustration:"placeholder",narrative:"A woman in plainclothes stops you — no uniform, but the posture is military. She says she knows who you are. Conversationally. Like weather.",choices:[{text:"Talk your way through (Ironwatch standing helps)",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:11},factionBonus:{factionId:"ironwatch",perTier:2},outcomes:{success:{text:"She listens and nods once. Whatever she decides, it's favorable. She tells you the patrol rotation ahead and wishes you a quiet road.",effects:[{type:"flag",key:"patrol_route_known",value:!0},{type:"morale",value:5},{type:"factionRep",factionId:"ironwatch",value:-5},{type:"log",text:"An Ironwatch informant let you through."}]},failure:{text:"She marks something in a ledger and steps aside. The report will reach the nearest post by nightfall.",effects:[{type:"morale",value:-10},{type:"flag",key:"ironwatch_spotted",value:!0},{type:"log",text:"An Ironwatch informant took note of you."}]}}},{text:"Bribe her (10 gold)",visibleCost:"10g",skillCheck:null,outcomes:{success:{text:"She pockets the coin without looking at it and walks away. Clean and quick. You've bought silence for a day, maybe two.",effects:[{type:"gold",value:-10},{type:"morale",value:-3},{type:"log",text:"You bribed an Ironwatch informant."}]},failure:{text:"",effects:[]}}}]},{id:"salt_flat_mirages",title:"THE WALKING THIRST",biomes:["salt_flats","cinderwaste"],weight:10,type:"danger",illustration:"placeholder",narrative:"The flats shimmer in every direction. Somewhere behind the heat-haze your sense of distance collapses and the horizon folds back on itself. Two in the party have been following a pool of water for an hour that was never there. Their lips are cracked and their eyes are wrong.",choices:[{text:"Orient using the sun and force a heading (Survival TN 9)",visibleCost:null,skillCheck:{skill:"survival",stat:"wit",tn:9},outcomes:{success:{text:"You plant your back to the sun and count paces. The shimmer is still there but you move through it like a dream you refuse. By dusk you are clear of the mirage zone, thirsty but whole.",effects:[{type:"water",value:-1},{type:"morale",value:3},{type:"log",text:"You navigated out of a heat-mirage on the salt flats."}]},failure:{text:"You march with confidence and end up two hours in the wrong direction before the mistake becomes undeniable. Water is running lower than it should be. Someone is crying quietly in the back.",effects:[{type:"water",value:-3},{type:"morale",value:-8}]}}},{text:"Make camp and wait for cooler air",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You pitch what shade you have and wait. The mirages thin as the temperature drops. You lose most of the day but you lose nothing worse.",effects:[{type:"water",value:-1},{type:"morale",value:-4}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"greywood_trap_line",title:"SOMEONE ELSE'S SNARES",biomes:["greywood","amber_forest"],weight:9,type:"danger",illustration:"placeholder",narrative:"The trail ahead is threaded with snares — wire loops at ankle height, pressure-triggers buried in leaf litter, a tripwire strung black against shadow. Someone has been hunting here recently. The question is what they were hunting.",choices:[{text:"Pick through carefully (Tracking TN 9)",visibleCost:null,skillCheck:{skill:"tracking",stat:"hed",tn:9},outcomes:{success:{text:"You read the pattern of them — old trapper's logic — and find the safe line through. You even collect three of the snares, which you might need later.",effects:[{type:"morale",value:4},{type:"log",text:"You disarmed a trap line and collected useful wire."}]},failure:{text:"A wire catches someone low on the shin and snaps tight before you can shout a warning. The cut is shallow but the humiliation stings deep.",effects:[{type:"damage",targetRandom:!0,value:5},{type:"morale",value:-4}]}}},{text:"Detour through the undergrowth",visibleCost:null,skillCheck:null,outcomes:{success:{text:"The brush is thick and slow-going. You lose an hour but arrive at the far side with nothing worse than scratches and lost tempers.",effects:[{type:"morale",value:-3}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"storm_coast_surge",title:"THE GREY SURGE",biomes:["storm_coast","fens"],weight:8,type:"danger",illustration:"placeholder",narrative:"The water comes without warning — a surge from the sea, brown and fast, swallowing the road up to the knee in seconds. The current drags at your ankles like a living thing.",choices:[{text:"Rope together and push through (Endurance TN 10)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:10},outcomes:{success:{text:"You lock arms and lean into it. The current screams against your shins but the chain holds. You reach high ground bruised, drenched, and alive.",effects:[{type:"morale",value:5},{type:"log",text:"You survived a coastal surge by holding together."}]},failure:{text:"The rope holds but not everyone's footing does. Someone goes under for a moment — you haul them back but their pack is gone.",effects:[{type:"damage",targetRandom:!0,value:6},{type:"food",value:-2},{type:"morale",value:-7}]}}},{text:"Climb off the road and wait it out",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You scramble onto a low wall and wait. The surge takes twenty minutes to recede. You press on.",effects:[{type:"morale",value:-4}]},failure:{text:"",effects:[]}}}],cooldown:3},{id:"hollow_reaches_sinkhole",title:"BAD GROUND",biomes:["hollow_reaches","fens"],weight:9,type:"danger",illustration:"placeholder",narrative:"The earth gives way with almost no warning — a soft sucking sound, then a section of trail opens beneath your lead walker's foot. They catch themselves on the edge but the ground around them is still moving.",choices:[{text:"Pull them back and find another path",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You haul them back and pick a route through the dense growth alongside. It takes twice as long but no one falls.",effects:[{type:"morale",value:-3}]},failure:{text:"",effects:[]}}},{text:"Test the ground ahead before crossing (Survival TN 8)",visibleCost:null,skillCheck:{skill:"survival",stat:"wit",tn:8},outcomes:{success:{text:"You probe with a walking stick and map the solid patches. You cross in single file without incident.",effects:[{type:"morale",value:5},{type:"log",text:"You read bad ground and found a safe crossing."}]},failure:{text:"Your probe misses a weak spot and your wrist follows it into cold black water. You wrench free but lose the stick and your confidence.",effects:[{type:"damage",targetRandom:!0,value:4},{type:"morale",value:-5}]}}}],cooldown:3},{id:"cinderwaste_firepocket",title:"POCKET FIRE",biomes:["cinderwaste","ashfields"],weight:8,type:"danger",illustration:"placeholder",narrative:"The ground vents here — hairline cracks in the crust leaking thin smoke. One ignites as you watch, a tongue of blue flame. The crust ahead looks stable but you know what's underneath.",choices:[{text:"Sprint across (Endurance TN 9)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:9},outcomes:{success:{text:"You pick your line and sprint it. The crust flexes but holds. You clear the vent-field in under a minute, coughing up blue smoke.",effects:[{type:"morale",value:5},{type:"log",text:"You ran a cinder vent-field without getting burned."}]},failure:{text:"A crust-section collapses and superheated gas vents into someone's face. They don't lose the eye, but it's close.",effects:[{type:"damage",targetRandom:!0,value:8},{type:"condition",id:"bleeding",name:"Burned",duration:2},{type:"morale",value:-8}]}}},{text:"Go the long way around",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Three hours longer. Your boots smell like smoke. Nobody is on fire.",effects:[{type:"water",value:-1},{type:"morale",value:-2}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"thorn_mere_sunken_shrine",title:"THE DROWNED ALTAR",biomes:["thorn_mere","fens"],weight:7,type:"discovery",illustration:"placeholder",narrative:"Wading through the shallows you stumble against smooth carved stone under the black water. An altar, sunk to the waist in peat. Offerings sit atop it: small things left very recently.",choices:[{text:"Study the carvings (Lore TN 9)",visibleCost:null,skillCheck:{skill:"lore",stat:"wit",tn:9},outcomes:{success:{text:"Wayfarers' Compact iconography — pre-schism, old chapter. The offerings are fresh within a week. Someone nearby still keeps the old ways.",effects:[{type:"flag",key:"wayfarer_shrine_found",value:!0},{type:"factionRep",factionId:"wayfarers_compact",value:3},{type:"morale",value:5},{type:"log",text:"You found a drowned Wayfarer shrine with fresh offerings."}]},failure:{text:"The symbols are worn and unfamiliar. Someone worships something here. You move on without understanding it.",effects:[{type:"morale",value:-3}]}}},{text:"Leave an offering",visibleCost:"1 food",skillCheck:null,outcomes:{success:{text:"You set down a piece of dried meat. It feels right, even if you can't say why.",effects:[{type:"food",value:-1},{type:"morale",value:4}]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"mountains_sealed_cache",title:"THE IRON CACHE",biomes:["mountains","east_march"],weight:6,type:"discovery",tags:["food_source","water_source"],illustration:"placeholder",narrative:"Set into the cliff face behind a waterfall is a small iron door, sealed with Ironwatch wax. Military supply cache, pre-collapse. The wax is old but unbroken.",choices:[{text:"Break the seal and take the supplies",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Emergency rations, clean water, rope, and a patrol map of the passes. Everything still good. The Ironwatch built things to last.",effects:[{type:"food",value:5},{type:"water",value:3},{type:"flag",key:"ironwatch_cache_opened",value:!0},{type:"factionRep",factionId:"ironwatch",value:-5},{type:"log",text:"You broke an Ironwatch military cache seal and took the supplies."}]},failure:{text:"",effects:[]}}},{text:"Report it to the Ironwatch (Lore TN 8)",visibleCost:null,skillCheck:{skill:"lore",stat:"wit",tn:8},outcomes:{success:{text:"You mark the cliff face with the Ironwatch's inspection symbol. If they still have anyone in the passes, they'll find it intact.",effects:[{type:"flag",key:"ironwatch_cache_reported",value:!0},{type:"factionRep",factionId:"ironwatch",value:8},{type:"morale",value:5}]},failure:{text:"You leave it sealed but mark the spot wrong. If the Ironwatch check, they'll find nothing useful in your message.",effects:[{type:"morale",value:-2}]}}}],cooldown:0},{id:"greywood_painted_trees",title:"THE MARKED WOOD",biomes:["greywood","amber_forest"],weight:8,type:"discovery",illustration:"placeholder",narrative:"Someone has been painting faces on the trees. Dozens of them, each a portrait, the paint red-brown. It might be ochre.",choices:[{text:"Understand the pattern (Tracking TN 9)",visibleCost:null,skillCheck:{skill:"tracking",stat:"hed",tn:9},outcomes:{success:{text:"A memorial. Each face on its own tree near the center, carefully arranged. Someone is memorializing everyone they've lost, by name.",effects:[{type:"flag",key:"painted_grove_understood",value:!0},{type:"morale",value:-5},{type:"log",text:"You understood the painted grove — a living memorial."}]},failure:{text:"The faces look at you from all sides. You move through quickly, not meeting their painted eyes.",effects:[{type:"morale",value:-6}]}}},{text:"Add a face of your own",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You use charcoal from the fire kit. When you step back, the face looks more like them than you expected. Grief is a strange teacher.",effects:[{type:"morale",value:6},{type:"log",text:"You painted a face in the memorial grove."}]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"hollows_stranded_child",title:"ALONE ON THE ROAD",biomes:["hollows","hollow_reaches"],weight:9,type:"moral",illustration:"placeholder",narrative:"She is maybe seven years old, sitting in the middle of the road with a pack half her size. She says she knows where her uncle lives but she hasn't been there before. She has been sitting here since yesterday morning.",choices:[{text:"Take her with you",visibleCost:"2 food",skillCheck:null,outcomes:{success:{text:"She walks in the middle of the party without speaking. On the second day she shows you the letter — a deed to her uncle's land, in her mother's hand. You deliver her. Her uncle is real. He weeps at the door.",effects:[{type:"food",value:-2},{type:"morale",value:12},{type:"log",text:"You delivered a child to her uncle. She was carrying a deed."}]},failure:{text:"",effects:[]}}},{text:"Give her food and directions (Survival TN 8)",visibleCost:"1 food",skillCheck:{skill:"survival",stat:"wit",tn:8},outcomes:{success:{text:"You draw her a clear map and describe every landmark. She sets off with the look of someone who will make it.",effects:[{type:"food",value:-1},{type:"morale",value:3}]},failure:{text:"You give her what you can but the directions are wrong, and you know it after she's already gone.",effects:[{type:"food",value:-1},{type:"morale",value:-9}]}}},{text:"Tell her you cannot help",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You walk past. The road asks this sometimes. Several in the party do not speak to each other for the rest of the day.",effects:[{type:"morale",value:-14}]},failure:{text:"",effects:[]}}}],cooldown:8},{id:"salt_traders_price",title:"THE PRICE OF THE PASS",biomes:["salt_flats","east_march"],weight:9,type:"moral",illustration:"placeholder",narrative:"The Salt Traders' checkpoint blocks the only passable road. The toll is steep — everything in your medicine kit. The guard shrugs: there's fever in the next settlement. He might be telling the truth.",choices:[{text:"Pay the toll — give up the medicine",visibleCost:"all medicine",skillCheck:null,outcomes:{success:{text:"You hand it over. Twenty paces down the road you see two children with fever on their cheeks. Maybe it was true.",effects:[{type:"medicine",value:-4},{type:"factionRep",factionId:"salt_traders_guild",value:5},{type:"morale",value:-3},{type:"log",text:"You surrendered your medicine to the checkpoint toll."}]},failure:{text:"",effects:[]}}},{text:"Negotiate — offer gold instead (Persuasion TN 10)",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:10},outcomes:{success:{text:"You make the case calmly: gold can buy medicine from the next town. He accepts fifteen gold. Not cheap, but better.",effects:[{type:"gold",value:-15},{type:"factionRep",factionId:"salt_traders_guild",value:2},{type:"morale",value:5}]},failure:{text:"He's heard every argument. The medicine or the road back.",effects:[{type:"medicine",value:-4},{type:"factionRep",factionId:"salt_traders_guild",value:-2},{type:"morale",value:-6}]}}},{text:"Find a way around (Survival TN 11)",visibleCost:null,skillCheck:{skill:"survival",stat:"wit",tn:11},outcomes:{success:{text:"A goat track adds a full day but skirts the checkpoint entirely. The medicine is still yours.",effects:[{type:"water",value:-1},{type:"morale",value:-4},{type:"factionRep",factionId:"salt_traders_guild",value:-3}]},failure:{text:"The goat track ends in a cliff. You backtrack in the dark and arrive at the checkpoint the next morning, having lost a day.",effects:[{type:"water",value:-2},{type:"medicine",value:-4},{type:"morale",value:-8},{type:"factionRep",factionId:"salt_traders_guild",value:-2}]}}}],cooldown:6},{id:"wounded_ironwatch",title:"BLOOD ON THE ROAD",biomes:["ironmarch","east_march"],weight:9,type:"moral",illustration:"placeholder",narrative:"An Ironwatch soldier lies in the ditch with a crossbow bolt in his thigh. Not going to bleed out but not walking anywhere. He's terrified, in pain, and alone.",choices:[{text:"Treat his wound (1 medicine)",visibleCost:"1 medicine",skillCheck:{skill:"healing",stat:"wit",tn:8},outcomes:{success:{text:"You pull the bolt, pack the wound. He grips your wrist as you work. When you finish he gives you his patrol cipher — a wooden disc that opens the next two checkpoints without inspection.",effects:[{type:"medicine",value:-1},{type:"flag",key:"ironwatch_cipher",value:!0},{type:"factionRep",factionId:"ironwatch",value:10},{type:"morale",value:8},{type:"log",text:"You saved an Ironwatch soldier and received his patrol cipher."}]},failure:{text:"You do what you can. He'll live, but it'll be a long recovery. He thanks you. He has nothing to give.",effects:[{type:"medicine",value:-1},{type:"factionRep",factionId:"ironwatch",value:4},{type:"morale",value:4}]}}},{text:"Leave water and move on",visibleCost:"1 water",skillCheck:null,outcomes:{success:{text:"More than most would do. Less than you could. The party debates this quietly for miles.",effects:[{type:"water",value:-1},{type:"morale",value:-5}]},failure:{text:"",effects:[]}}},{text:"Walk past him",visibleCost:null,skillCheck:null,outcomes:{success:{text:"He watches you pass with eyes that hold no accusation, which is somehow worse.",effects:[{type:"morale",value:-10},{type:"factionRep",factionId:"ironwatch",value:-6}]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"amber_forest_resin",title:"AMBER FLOW",biomes:["amber_forest","greywood"],weight:10,type:"opportunity",illustration:"placeholder",narrative:"A tree the size of a house has split, and from the wound runs thick amber resin in slow golden ropes. The smell is sharp and medicinal.",choices:[{text:"Harvest as much as possible (Nature TN 8)",visibleCost:null,skillCheck:{skill:"nature",stat:"hed",tn:8},outcomes:{success:{text:"You render it into containers from your kit. Enough to use as medicine and sell the excess.",effects:[{type:"medicine",value:3},{type:"gold",value:10},{type:"log",text:"You harvested amber resin — worth real coin."}]},failure:{text:"The resin gets everywhere. You salvage a little but mostly you're just sticky.",effects:[{type:"medicine",value:1},{type:"morale",value:-3}]}}},{text:"Take only what fits in your medicine kit",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You fill what space you have carefully. It's not much, but it's good material.",effects:[{type:"medicine",value:2}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"steppe_buried_trade_box",title:"THE BURIED BOX",biomes:["steppe","east_march"],weight:8,type:"opportunity",illustration:"placeholder",narrative:"Your boot catches the edge of something buried — a wooden crate sealed with wax, recently buried, the turned earth still darker than what surrounds it. No marker.",choices:[{text:"Dig it up",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Trade goods: cloth, lamp oil, and a pouch of salt-guild coin. A runner's cache — unofficial or contraband.",effects:[{type:"fuel",value:3},{type:"gold",value:18},{type:"morale",value:4},{type:"factionRep",factionId:"salt_traders_guild",value:-4},{type:"log",text:"You dug up a smuggler's cache. Salt guild coin and lamp oil."}]},failure:{text:"",effects:[]}}},{text:"Mark it for the Salt Traders (Trade TN 8)",visibleCost:null,skillCheck:{skill:"trade",stat:"wit",tn:8},outcomes:{success:{text:"You leave the guild's road-mark. That kind of reputation has value.",effects:[{type:"factionRep",factionId:"salt_traders_guild",value:7},{type:"morale",value:5}]},failure:{text:"You get the mark wrong. You've just told any guild runner that someone was messing with their cache.",effects:[{type:"factionRep",factionId:"salt_traders_guild",value:-3},{type:"morale",value:-2}]}}}],cooldown:5},{id:"fens_crane_colony",title:"THE GREY CRANES",biomes:["fens","thorn_mere"],weight:9,type:"opportunity",tags:["food_source"],illustration:"placeholder",narrative:"A colony of grey cranes has nested on the fen islets — dozens of them, tall and still as reeds. Their eggs will be in the nests. You haven't had fresh food in longer than you'd like to count.",choices:[{text:"Raid the nests for eggs (Stealth TN 9)",visibleCost:null,skillCheck:{skill:"stealth",stat:"edg",tn:9},outcomes:{success:{text:"You take only from the outer nests. Enough eggs for a hot meal tonight and tomorrow both.",effects:[{type:"food",value:5},{type:"morale",value:7},{type:"log",text:"You raided a crane colony for eggs without spooking them."}]},failure:{text:"You panic the birds. The whole colony erupts in noise and snapping beaks. Two eggs and a bruise.",effects:[{type:"food",value:2},{type:"morale",value:-3},{type:"damage",targetRandom:!0,value:2}]}}},{text:"Leave the birds alone",visibleCost:null,skillCheck:null,outcomes:{success:{text:"They watch you pass with amber eyes. Some things should be left undisturbed.",effects:[{type:"morale",value:2}]},failure:{text:"",effects:[]}}}],cooldown:3},{id:"mountains_fuel_cache",title:"THE PINE RESIN STORE",biomes:["mountains","greywood"],weight:8,type:"opportunity",illustration:"placeholder",narrative:"Tucked under an overhang is a neat stack of pine-resin bricks, wrapped in oilcloth. Someone cut and stored these for the season. There are signs someone camped here within the last week.",choices:[{text:"Take the fuel",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You load as much as you can reasonably carry. Whoever left this will have to start over. That's the world now.",effects:[{type:"fuel",value:5},{type:"morale",value:-4},{type:"log",text:"You took a pine-resin fuel store someone had prepared."}]},failure:{text:"",effects:[]}}},{text:"Leave coin and a note (–8 gold)",visibleCost:"8 gold",skillCheck:null,outcomes:{success:{text:"Fair trade, or as close as you can manage. If they find it, maybe they'll know not everyone is just taking.",effects:[{type:"fuel",value:5},{type:"gold",value:-8},{type:"morale",value:8},{type:"factionRep",factionId:"wayfarers_compact",value:2}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"east_march_collapsed_tower",title:"THE FALLEN TOWER",biomes:["east_march","ironmarch"],weight:7,type:"exploration",tags:["food_source"],illustration:"placeholder",narrative:"The watchtower has come down, its stone scattered across a hundred yards of scrubland. The base is still standing. From height you might see the road ahead.",choices:[{text:"Climb and look out (Perception TN 8)",visibleCost:null,skillCheck:{skill:"tracking",stat:"hed",tn:8},outcomes:{success:{text:"A patrol column, two days out, moving this direction. And a ford crossing you'd have missed at ground level.",effects:[{type:"flag",key:"patrol_spotted_ahead",value:!0},{type:"flag",key:"hidden_ford_known",value:!0},{type:"morale",value:5},{type:"log",text:"From the fallen tower you spotted a patrol and a hidden ford."}]},failure:{text:"The view is hazy. Nothing resolves. The climb cost you time and a scraped knee.",effects:[{type:"damage",targetRandom:!0,value:1},{type:"morale",value:-2}]}}},{text:"Search the rubble (Survival TN 9)",visibleCost:null,skillCheck:{skill:"survival",stat:"hed",tn:9},outcomes:{success:{text:"A scout's kit under a fallen block: a march map, tin compass, and three days of hard tack sealed in wax.",effects:[{type:"food",value:3},{type:"flag",key:"march_map_found",value:!0},{type:"morale",value:4},{type:"log",text:"You found a scout's kit in the fallen watchtower rubble."}]},failure:{text:"The rubble yields nothing but broken stone.",effects:[]}}}],cooldown:5},{id:"hollows_night_pool",title:"THE STILL POOL",biomes:["hollows","thorn_mere"],weight:7,type:"exploration",tags:["water_source"],illustration:"placeholder",narrative:"Making camp beside a black pool, you notice it does not reflect the sky correctly. The stars in its surface are a different arrangement. You stare into it for too long.",choices:[{text:"Study the pool (Lore TN 11)",visibleCost:null,skillCheck:{skill:"lore",stat:"wit",tn:11},outcomes:{success:{text:"A remnant pool — the membrane between what-is and what-was has worn thin. The stars it shows are pre-collapse. If you focus, you can see the old road in its surface — the true path to the Gate.",effects:[{type:"flag",key:"remnant_pool_understood",value:!0},{type:"flag",key:"true_road_glimpsed",value:!0},{type:"morale",value:-3},{type:"log",text:"The still pool showed you the pre-collapse road."}]},failure:{text:"You have no framework for what you're seeing. The wrongness settles in your chest. You move camp to higher ground.",effects:[{type:"morale",value:-8}]}}},{text:"Fill water skins from it",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Cold and clear and tasteless. That night two members dream of places they've never been, in perfect detail. They wake disturbed.",effects:[{type:"water",value:3},{type:"morale",value:-6},{type:"condition",id:"exhausted",name:"Dream-Struck",duration:1}]},failure:{text:"",effects:[]}}}],cooldown:6},{id:"wayfarer_checkpoint_scout",title:"THE COMPACT RUNNER",biomes:["steppe","ashfields","east_march"],weight:10,type:"social",illustration:"placeholder",narrative:"A young woman sits at a fire, eating quickly and with the efficiency of someone who never stays long. Her pack carries the Wayfarers' Compact ribbon.",choices:[{text:"Sit and trade information (Persuasion TN 7)",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:7},outcomes:{success:{text:"She knows the road ahead — washed-out bridge, toll point, working healer. She gives you a compact token for a warm meal at any Wayfarer waystation.",effects:[{type:"flag",key:"wayfarer_road_intel",value:!0},{type:"factionRep",factionId:"wayfarers_compact",value:6},{type:"morale",value:7},{type:"log",text:"A Compact runner shared road intelligence."}]},failure:{text:"She's polite but guarded and packs up before the conversation goes anywhere.",effects:[{type:"morale",value:-2}]}}},{text:"Warm yourselves at her fire in silence",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Twenty minutes of comfortable silence. When you leave, she raises two fingers in the Compact salute. You return it without thinking.",effects:[{type:"morale",value:4},{type:"factionRep",factionId:"wayfarers_compact",value:1}]},failure:{text:"",effects:[]}}}],cooldown:5},{id:"storm_coast_fishing_village",title:"THE LAST VILLAGE",biomes:["storm_coast","fens"],weight:8,type:"social",tags:["food_source","water_source"],illustration:"placeholder",narrative:"The village has maybe forty people left. Their headman is a woman in her sixties who looks at your party the way someone looks at a difficult sum.",choices:[{text:"Trade plainly (Persuasion TN 8)",visibleCost:null,skillCheck:{skill:"persuasion",stat:"rch",tn:8},outcomes:{success:{text:"She respects plainness. An hour of bartering: smoked fish, fresh water, and an invitation to sleep in the fish shed loft. The community is alive. That is its own miracle.",effects:[{type:"food",value:5},{type:"water",value:3},{type:"morale",value:9},{type:"log",text:"The last coast village traded with you and gave you shelter."}]},failure:{text:"You come across as threatening. The headman closes the gate. You camp outside.",effects:[{type:"morale",value:-6}]}}},{text:"Offer to work for a meal (Endurance TN 7)",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:7},outcomes:{success:{text:"Three hours hauling nets. You eat at their table — salted fish and root porridge — and morale climbs back toward something like human.",effects:[{type:"food",value:4},{type:"water",value:2},{type:"morale",value:10},{type:"log",text:"You worked for your meal in the fishing village."}]},failure:{text:"The work is specialized and you slow them down. The headman gives you a small meal anyway. Charity, not commerce.",effects:[{type:"food",value:2},{type:"morale",value:2}]}}}],cooldown:6},{id:"fishing_spot",title:"A STILL POOL",biomes:["greywood","hollows","mountains","storm_coast"],weight:4,type:"opportunity",tags:["food_source","water_source"],illustration:"placeholder",narrative:"The trail dips beside a clear pool fed by a cold spring. Something moves beneath the surface.",choices:[{text:"Fish with a line (Nature TN 7)",visibleCost:null,skillCheck:{skill:"nature",stat:"hed",tn:7},outcomes:{success:{text:"You pull several fish from the pool. The cold spring water fills your containers while you work.",effects:[{type:"food",value:3},{type:"water",value:1},{type:"log",text:"You pulled several fish from the pool."}]},failure:{text:"You catch one small fish after an hour of patience.",effects:[{type:"food",value:1},{type:"log",text:"You catch one small fish after an hour."}]}}},{text:"Collect water only",visibleCost:null,skillCheck:null,outcomes:{success:{text:"The spring water is clean and cold. You fill every container you have.",effects:[{type:"water",value:2},{type:"log",text:"The spring water is clean and cold."}]},failure:{text:"",effects:[]}}},{text:"Press on",visibleCost:null,skillCheck:null,outcomes:{success:{text:"The road calls. The pool disappears behind the treeline.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:3},{id:"watering_hole",title:"WATERING HOLE",biomes:["ashfields","salt_flats","ironmarch","blighted_wastes"],weight:5,type:"opportunity",tags:["water_source"],illustration:"placeholder",narrative:"A muddy depression in the earth holds brackish water. It smells of minerals but looks drinkable. Animals have been here recently.",choices:[{text:"Drink and fill containers",visibleCost:null,skillCheck:null,outcomes:{success:{text:"The water is harsh but welcome. You drink deeply and fill your containers, stomach clenching at the mineral bite.",effects:[{type:"water",value:3},{type:"condition",id:"nauseous",name:"Nauseous",duration:1},{type:"log",text:"The water was harsh but welcome."}]},failure:{text:"",effects:[]}}},{text:"Purify first (–1 Medicine)",visibleCost:"1 medicine",skillCheck:null,outcomes:{success:{text:"You take the time to boil the water with a medicine pouch. It tastes better. It is better.",effects:[{type:"medicine",value:-1},{type:"water",value:4},{type:"log",text:"You purified the brackish water. It tastes better."}]},failure:{text:"",effects:[]}}},{text:"Leave it",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You eye the murky water and walk on. Thirst is a known quantity; whatever is in that pool is not.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"berry_thicket",title:"WILD BERRIES",biomes:["greywood","ashfields","hollows"],weight:4,type:"opportunity",tags:["food_source"],illustration:"placeholder",narrative:"Dark berries cling to thorned branches along the path. They could be edible — or they could be something worse.",choices:[{text:"Identify them (Nature TN 6)",visibleCost:null,skillCheck:{skill:"nature",stat:"hed",tn:6},outcomes:{success:{text:"These are safe. You eat well, filling your pack with the remainder.",effects:[{type:"food",value:2},{type:"morale",value:3},{type:"log",text:"You identified the berries as safe and ate well."}]},failure:{text:"Some were fine. Others weren't. You're not sure which ones did it.",effects:[{type:"food",value:1},{type:"morale",value:-1},{type:"condition",id:"nauseous",name:"Nauseous",duration:2},{type:"log",text:"Some berries were fine. Others weren't."}]}}},{text:"Eat without checking",visibleCost:null,skillCheck:{skill:"endurance",stat:"grt",tn:7},outcomes:{success:{text:"You eat quickly and hope for the best. Your stomach protests mildly but settles. Not poisoned. This time.",effects:[{type:"food",value:2},{type:"log",text:"You ate without checking. It was fine."}]},failure:{text:"You eat quickly and hope for the best. The hope was misplaced.",effects:[{type:"food",value:2},{type:"morale",value:-2},{type:"condition",id:"nauseous",name:"Nauseous",duration:2},{type:"log",text:"You ate without checking. Some of the berries were wrong."}]}}},{text:"Leave them",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Not worth the risk. You walk past the thicket and try not to think about your hunger.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:3},{id:"abandoned_campfire",title:"COLD ASHES",biomes:["ashfields","greywood","hollows","mountains","salt_flats","ironmarch","blighted_wastes","storm_coast"],weight:3,type:"discovery",illustration:"placeholder",narrative:"Someone camped here recently. The fire is cold but the site is intact — they left in a hurry, or didn't leave at all.",choices:[{text:"Search the area (Perception TN 7)",visibleCost:null,skillCheck:{skill:"perception",stat:"hed",tn:7},outcomes:{success:{text:"Tucked under a flat stone you find a cloth-wrapped bundle: travel rations, sealed tight. Someone packed these to come back for them.",effects:[{type:"food",value:2},{type:"medicine",value:1},{type:"log",text:"You found hidden supplies at an abandoned campsite."}]},failure:{text:"Just cold ashes and a few sticks. Whatever was here is gone.",effects:[{type:"food",value:1},{type:"log",text:"You found little at the abandoned camp — just cold ashes and a few sticks."}]}}},{text:"Rest briefly",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You take comfort that others have passed this way — and passed through. Someone made it this far.",effects:[{type:"morale",value:1},{type:"log",text:"You rested at an abandoned camp. Others have passed this way."}]},failure:{text:"",effects:[]}}},{text:"Keep moving",visibleCost:null,skillCheck:null,outcomes:{success:{text:"The road goes on.",effects:[]},failure:{text:"",effects:[]}}}],cooldown:0},{id:"injured_animal",title:"A WOUNDED BEAST",biomes:["greywood","ashfields","hollows","mountains"],weight:3,type:"moral",tags:["food_source"],illustration:"placeholder",narrative:"A deer — or what used to resemble one — lies in the brush, its leg broken. It watches you with dark eyes.",choices:[{text:"Put it out of its misery and take the meat",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You do what must be done. It looks too human in the eyes, but you do it anyway. The meat will last a day at least.",effects:[{type:"food",value:3},{type:"morale",value:-1},{type:"log",text:"You put the animal out of its misery and took the meat."}]},failure:{text:"",effects:[]}}},{text:"Treat the wound (Nature TN 8)",visibleCost:null,skillCheck:{skill:"nature",stat:"hed",tn:8},outcomes:{success:{text:"The animal stands and limps away, watching you once before vanishing into the brush. It feels like something.",effects:[{type:"morale",value:2},{type:"item",itemId:"ember_stone"},{type:"log",text:"You treated the animal's wound. It stood and walked away."}]},failure:{text:"You try but the wound is too deep. In the end you take what meat you can. Not what you hoped for.",effects:[{type:"food",value:1},{type:"log",text:"The animal could not be saved."}]}}},{text:"Walk past",visibleCost:null,skillCheck:null,outcomes:{success:{text:"You leave it to its fate. It doesn't cry out.",effects:[{type:"morale",value:1},{type:"log",text:"You walked past and left the animal to its fate."}]},failure:{text:"",effects:[]}}}],cooldown:4},{id:"ruins_cache",title:"HIDDEN CACHE",biomes:["ironmarch","blighted_wastes","salt_flats"],weight:2,type:"discovery",illustration:"placeholder",narrative:"A loose stone in a crumbling wall conceals a hollow. Someone hid something here long ago.",choices:[{text:"Open it (Perception TN 7)",visibleCost:null,skillCheck:{skill:"perception",stat:"hed",tn:7},outcomes:{success:{text:"Inside: dried rations, two gold coins, and wrapped in oilcloth — a small glowing stone, still warm. Someone buried this with intention.",effects:[{type:"food",value:2},{type:"gold",value:2},{type:"item",itemId:"traveler_talisman"},{type:"flag",key:"ruins_cache_opened",value:!0},{type:"log",text:"You found a hidden cache in the ruined wall."}]},failure:{text:"The stone is stuck fast or you misread the wall. You find nothing but dust.",effects:[{type:"food",value:1},{type:"log",text:"You found only dust in the ruined wall."}]}}},{text:"Leave it sealed",visibleCost:null,skillCheck:null,outcomes:{success:{text:"Someone hid this with care. You leave it for them, or whoever comes after.",effects:[{type:"morale",value:1},{type:"flag",key:"ruins_cache_left",value:!0}]},failure:{text:"",effects:[]}}}],cooldown:10}],r=[{id:"hint_pace",text:"Pace affects daily resource use. Fast pace burns more food and water but covers ground quicker.",condition:t=>(t.dayNumber??1)===1},{id:"hint_morale",text:"Morale below 30 causes penalties on skill checks. Feed the party, rest when hurt, and keep moving.",condition:t=>{var e;return(((e=t.party)==null?void 0:e.morale)??75)<40}},{id:"hint_conditions",text:"Conditions like Bleeding or Exhausted deal HP damage each day. Use Medicine or rest to clear them.",condition:t=>{var e,a;return(a=(e=t.party)==null?void 0:e.members)==null?void 0:a.some(o=>{var s;return!o.isDead&&((s=o.conditions)==null?void 0:s.length)>0})}},{id:"hint_water_critical",text:"Running out of water applies Dehydrated — 2 HP/day. Prioritize finding water over food.",condition:t=>{var e,a;return(((a=(e=t.journey)==null?void 0:e.resources)==null?void 0:a.water)??99)<=3}},{id:"hint_food_critical",text:"Starving characters lose 1 HP/day. A starving AND dehydrated character becomes Frail and loses even more.",condition:t=>{var e,a;return(((a=(e=t.journey)==null?void 0:e.resources)==null?void 0:a.food)??99)<=3}},{id:"hint_escalation",text:"Threat Escalation rises each day. Higher escalation means more frequent and dangerous encounters.",condition:t=>{var e;return(((e=t.world)==null?void 0:e.escalation)??0)>=40}},{id:"hint_boss",text:"A major threat looms. These confrontations are rare but brutal — prepare before pressing on.",condition:t=>{var e;return(((e=t.world)==null?void 0:e.escalation)??0)>=60}},{id:"hint_town",text:"Towns reduce threat escalation and let you restock. Seek them when the road grows dangerous.",condition:t=>{var e,a,o;return(((e=t.world)==null?void 0:e.escalation)??0)>=50&&(((o=(a=t.world)==null?void 0:a.visitedSettlements)==null?void 0:o.length)??0)===0}}];function n(t){for(const e of r)if(localStorage.getItem(e.id)!=="dismissed"&&e.condition(t))return e;return null}function h(t){localStorage.setItem(t,"dismissed")}const u=[{term:"Grit",definition:"Raw physical toughness — how much punishment a body can take before it stops working. High Grit means you keep standing when others drop."},{term:"Edge",definition:"Precision, speed, and weapon skill. Edge determines whether your blade finds its mark or chases air."},{term:"Will",definition:"Mental fortitude and force of presence. Will sustains you against terror, exhaustion, and the slow rot of despair."},{term:"Wit",definition:"Intelligence, memory, and situational cunning. Wit lets you read a situation before it kills you and occasionally find a third option."},{term:"Reach",definition:"Social skill and persuasive force — how far your words carry in a world that rarely listens. Reach opens doors that blades cannot."},{term:"Head",definition:"Awareness, instinct, and the ability to notice things before they notice you. A good Head has saved more lives than good armor."},{term:"Morale",definition:"The collective will of your party to press on. When Morale breaks, people make desperate choices — or stop making choices at all."},{term:"Conditions",definition:"Persistent status effects that hamper your party: wounds that won't close, illness that spreads, fear that lingers. Most worsen if ignored."},{term:"Escalation",definition:"A measure of rising danger in an encounter. Each round without resolution tightens the noose — enemies coordinate, options narrow, costs climb."},{term:"Pace",definition:"The speed at which your party travels. Push the Pace to cover ground faster; suffer for it in resources, fatigue, and missed details."},{term:"Biome",definition:"A distinct region of the dying world — Ashfields, Rotwood, the Pale Wastes. Each biome carries its own hazards, encounters, and available resources."},{term:"Encounter",definition:"An event that interrupts your journey and demands a response. Encounters may be threats, opportunities, or something in between — often all three."},{term:"Fuel",definition:"The resource that keeps your fire burning and your camp habitable. Without Fuel, nights grow cold and conditions compound."},{term:"Provisions",definition:"Carried food and water. Provisions deplete each day of travel; running out begins the slow cascade toward Starving and Dehydrated."},{term:"Bleeds",definition:"An active wound condition causing HP loss each turn until treated. Left alone long enough, a Bleed will finish what the enemy started."},{term:"Starving",definition:"The condition imposed when provisions run dry. Starving characters suffer stat penalties that worsen by the day — the road does not wait."},{term:"Dehydrated",definition:"Water deprivation imposes faster and harsher penalties than hunger. A Dehydrated character deteriorates rapidly; two days without water is a death sentence."},{term:"Frail",definition:"A condition marking a character near their limit — reduced maximum HP, impaired checks, and a hairsbreadth from collapse. Rest may recover it; more punishment will not."},{term:"Bond",definition:"The connection between party members, forged through shared suffering. High Bond grants mechanical bonuses; losing a Bonded companion carries real Morale cost."},{term:"Epitaph",definition:"The record written at a character's death, assembled from their journey data. It is the only thing permadeath leaves behind — and sometimes, it is enough."}],d={deliver_message:{id:"deliver_message",factionId:"wayfarers_compact",title:"Carry the Sealed Letter",description:"A Compact courier pressed a sealed letter into your hands outside Ashford — urgent business, no questions asked. The recipient is waiting in Greyveil. Every day the letter sits unopened, someone goes without critical news.",objective:"Arrive in Greyveil with the sealed letter.",reward:{gold:15,rep:20},completionFlag:"arrived_greyveil_with_letter",availableAt:["ashford"]},clear_ash_road:{id:"clear_ash_road",factionId:"wayfarers_compact",title:"Clear the Ash Road",description:"Compact scouts report a stretch of the ashfields road has become too dangerous for their supply wagons — something has been ambushing travelers. They need proof the threat is dealt with. Survive three dangerous encounters in the ashfields and the Compact will consider the road clear.",objective:"Survive 3 danger encounters in the ashfields biome.",reward:{gold:25,rep:25},completionFlag:"ash_road_cleared",availableAt:["ashford","greyveil"]},report_deserters:{id:"report_deserters",factionId:"ironwatch",title:"Report the Deserters",description:"The Ironwatch garrison at Greyveil is hunting a band of deserters who broke from the Legion near Ford's crossing. If you've already located their hiding spot, the garrison commander will pay well for the intelligence. No heroics required — just talk.",objective:"Report the deserters' location to the Ironwatch garrison.",reward:{gold:20,rep:30},completionFlag:"deserter_ford_known",availableAt:["greyveil"]},recover_legion_relic:{id:"recover_legion_relic",factionId:"ironwatch",title:"Recover the Legion Relic",description:"A Legion standard was lost when the Ironmarch garrison fell years ago. The Ironwatch believes it's still out there, somewhere in the ironmarch wastes. They're not asking you to find it — just to prove you've walked the ground where it was lost.",objective:"Reach the ironmarch biome.",reward:{gold:30,rep:30},completionFlag:"reached_ironmarch",availableAt:["greyveil"]},escort_merchant:{id:"escort_merchant",factionId:"salt_traders_guild",title:"Escort the Merchant",description:"A Guild merchant needs reliable escorts for a shipment bound for Saltmere. The salt flats are no place for an unarmed wagon. Your job is simple: reach Saltmere with the shipment intact. The Guild pays on delivery, no questions about what you do on the road.",objective:"Arrive in Saltmere.",reward:{gold:35,rep:25},completionFlag:"arrived_saltmere",availableAt:["ashford","greyveil"]},price_assessment:{id:"price_assessment",factionId:"salt_traders_guild",title:"Price Assessment Survey",description:"The Guild's accountants want current market data from every settlement on the main trade route. A traveling party is the perfect cover — visit all three towns and the Guild's factor in Saltmere will compensate you generously for the intelligence.",objective:"Visit all three towns: Ashford, Greyveil, and Saltmere.",reward:{gold:40,rep:35},completionFlag:"visited_all_three_towns",availableAt:["ashford","greyveil","saltmere"]},map_the_wastes:{id:"map_the_wastes",factionId:"wayfarers_compact",title:"Map the Ironmarch Wastes",description:"The Compact's cartographers have outdated maps of the ironmarch. They need accurate route data — where the safe rest points are, which roads are washed out, and what dangers travelers face. Reach the ironmarch and return to any Compact-affiliated town.",objective:"Reach the ironmarch biome, then arrive at any town.",reward:{gold:30,rep:30},completionFlag:"returned_from_ironmarch",availableAt:["ashford","greyveil"]},break_the_siege:{id:"break_the_siege",factionId:"ironwatch",title:"Break the Siege",description:"A Legion outpost on the eastern route is cut off — encircled by hostile forces, no way in or out. The Ironwatch believes a small party moving fast could slip through and deliver critical supplies. The outpost commander will sign off on the contract once you arrive.",objective:"Reach Saltmere with at least 3 medicine.",reward:{gold:45,rep:40},completionFlag:"saltmere_with_medicine",availableAt:["greyveil"]},dead_letters:{id:"dead_letters",factionId:null,title:"Dead Letters",description:"A gravedigger pressed a bundle of unsent letters into your hands outside Ashford — letters recovered from the dead on the road. No faction, no reward beyond coin. Someone paid him to find a courier willing to carry them onward to wherever family might still be waiting.",objective:"Arrive in Saltmere.",reward:{gold:20,rep:0},completionFlag:"arrived_saltmere",availableAt:["ashford"]},survive_the_dark:{id:"survive_the_dark",factionId:"wayfarers_compact",title:"Survive the Dark",description:"A Compact officer is quietly offering a bonus to any party who survives until nightfall past the ashen road without calling for help. No mission, no objective beyond endurance — just proof that capable travelers can make it through the worst the road has to offer.",objective:"Survive 5 combat encounters.",reward:{gold:35,rep:20},completionFlag:"survived_five_combats",availableAt:["ashford","greyveil","saltmere"]}},c={dried_meat:{id:"dried_meat",name:"Dried Meat",cost:3,category:"food",effect:{food:3}},water_flask:{id:"water_flask",name:"Water Flask",cost:2,category:"water",effect:{water:2}},bandage:{id:"bandage",name:"Bandage",cost:4,category:"medicine",effect:{medicine:1}},torch:{id:"torch",name:"Torch",cost:1,category:"fuel",effect:{fuel:2}},rope:{id:"rope",name:"Rope",cost:5,category:"gear",effect:{}},medicine_kit:{id:"medicine_kit",name:"Medicine Kit",cost:12,category:"medicine",effect:{medicine:4}},iron_ration:{id:"iron_ration",name:"Iron Rations",cost:8,category:"food",effect:{food:8}},lantern:{id:"lantern",name:"Lantern",cost:7,category:"fuel",effect:{fuel:6}},healing_draught:{id:"healing_draught",name:"Healing Draught",cost:18,category:"medicine",effect:{heal:8}},quality_rope:{id:"quality_rope",name:"Quality Rope",cost:10,category:"gear",effect:{}},salt_preserve:{id:"salt_preserve",name:"Salt Preserves",cost:6,category:"food",effect:{food:6}},iron_dagger:{id:"iron_dagger",name:"Iron Dagger",cost:10,category:"weapon",effect:{weapon:"iron_dagger"}},short_sword:{id:"short_sword",name:"Short Sword",cost:14,category:"weapon",effect:{weapon:"short_sword"}},hand_axe_cat:{id:"hand_axe_cat",name:"Hand Axe",cost:12,category:"weapon",effect:{weapon:"hand_axe_cat"}},hunting_bow_std:{id:"hunting_bow_std",name:"Hunting Bow",cost:12,category:"weapon",effect:{weapon:"hunting_bow_std"}},spear:{id:"spear",name:"Spear",cost:10,category:"weapon",effect:{weapon:"spear"}},war_club:{id:"war_club",name:"War Club",cost:10,category:"weapon",effect:{weapon:"war_club"}},steel_sword:{id:"steel_sword",name:"Steel Sword",cost:30,category:"weapon",effect:{weapon:"steel_sword"}},war_hammer:{id:"war_hammer",name:"War Hammer",cost:28,category:"weapon",effect:{weapon:"war_hammer"}},longbow:{id:"longbow",name:"Longbow",cost:28,category:"weapon",effect:{weapon:"longbow"}},padded_vest:{id:"padded_vest",name:"Padded Vest",cost:8,category:"armor",effect:{armor:"padded_vest"}},road_leathers:{id:"road_leathers",name:"Road Leathers",cost:15,category:"armor",effect:{armor:"road_leathers"}},iron_vest:{id:"iron_vest",name:"Iron Vest",cost:30,category:"armor",effect:{armor:"iron_vest"}},chainmail:{id:"chainmail",name:"Chainmail",cost:40,category:"armor",effect:{armor:"chainmail"}},stolen_rations:{id:"stolen_rations",name:"Stolen Rations",cost:4,category:"black",effect:{food:5}},tainted_water:{id:"tainted_water",name:"Tainted Water",cost:2,category:"black",effect:{water:3}},war_surplus_kit:{id:"war_surplus_kit",name:"War Surplus Kit",cost:10,category:"black",effect:{medicine:3,fuel:2}},smuggled_elixir:{id:"smuggled_elixir",name:"Smuggled Elixir",cost:22,category:"black",effect:{heal:12}},forged_papers:{id:"forged_papers",name:"Forged Papers",cost:15,category:"black",effect:{morale:8}},ash_moonshine:{id:"ash_moonshine",name:"Ash Moonshine",cost:8,category:"black",effect:{morale:15}}};export{i as C,l as E,u as G,d as Q,c as S,h as d,n as g};
